INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('woodbridge', '2026-04-29 05:41:08.920051', 3400.2223362668137, NULL, NULL, NULL, 0.064, 75.46, 2.48, 79.4, 62.0, 69.0, '["2nWey4MCXW4", "CjuIZ2qdO5E", "U3HD51SY76Q", "84vX4334odw", "Th_4J195uAc", "HGAaEys0P1w", "-8PTPy8HsmU"]', '[{"id": "Ugw6UZCj9CyxpiJ6ew94AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\r\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-01-20T02:19:27Z", "parent_id": null, "video_id": "2nWey4MCXW4"}, {"id": "Ugw6UZCj9CyxpiJ6ew94AaABAg.9l5BGaKaWN8ADN6xqYs8zt", "text": "How much rent for 1 bedroom apartment / condo ?", "author": "@mirashahh789", "like_count": 0, "published_at": "2025-01-16T20:38:34Z", "parent_id": "Ugw6UZCj9CyxpiJ6ew94AaABAg", "video_id": "2nWey4MCXW4"}, {"id": "UgyJPDVuHCU5_EuN9Mh4AaABAg", "text": "I live in Woodbridge and I love it \ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T19:50:59Z", "parent_id": null, "video_id": "2nWey4MCXW4"}, {"id": "UgyIOY_28GJZsCehMAt4AaABAg", "text": "Please check your mail, I''ve sent a message about your YouTube Channel", "author": "@dhrubaofficial8211", "like_count": 0, "published_at": "2023-01-22T19:28:59Z", "parent_id": null, "video_id": "2nWey4MCXW4"}, {"id": "UgzXiGW3h07I8XRT1Xh4AaABAg", "text": "I live in Woodbridge and I LOVE it \ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-16T23:46:23Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgxZkA8XysvS4sVEyj54AaABAg", "text": "I grew up in the houses along the lake in the beginning of the video.  I forgot if it was either north or south lake. It was in the 80s. Went to stonecreek elementary.  It was such a fun time.  I miss it. \ud83d\ude22", "author": "@SPChef1981", "like_count": 1, "published_at": "2022-11-22T15:27:51Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgwjLtfwZW1QUE-SI8h4AaABAg", "text": "Thanks for the video.  I grew up in Woodbridge. Went to Eastshore elementary and lake side middle school. Haven''t seen cali in a minute thanks again.", "author": "@DaProblem850", "like_count": 1, "published_at": "2022-04-10T20:59:20Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgzXMkop908aVOnMKLl4AaABAg", "text": "Do a video on Great Park Neighborhoods", "author": "@kasufert", "like_count": 0, "published_at": "2022-02-24T07:15:16Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgzXMkop908aVOnMKLl4AaABAg.9YoznS30RIq9YpQntJtNxs", "text": "Wait just realized you already have one on it lol", "author": "@kasufert", "like_count": 0, "published_at": "2022-02-24T11:20:00Z", "parent_id": "UgzXMkop908aVOnMKLl4AaABAg", "video_id": "U3HD51SY76Q"}, {"id": "Ugxv6piQI6LLvHU_HRV4AaABAg", "text": "Nice content! The theme song from the OC plays in my head every time I see y''all. Maybe it''s a sign?", "author": "@TheKevinNewsom", "like_count": 1, "published_at": "2021-12-25T03:21:59Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgxoygHISmWeRBUzLU14AaABAg", "text": "We bought our 4 bedroom home down here in Laguna Hills back in 2009 for 500K and the price has doubled now. Best place to live with no HOA or Mello Roos tax.", "author": "@LagunaRider1961", "like_count": 2, "published_at": "2021-12-24T20:16:31Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgwIEDS_I4vkR8d7D1F4AaABAg", "text": "Great videos! Love your content! I just think it gets too chilly in the winter near the beach especially how it is more windy with the cold sea breeze. During summer it''s perfect to me though. I prefer inland during winter due to higher warmer daytime Temps compared to the daytime Temps near the beach areas during winter or cold months.", "author": "@GregoryMorales-uo6ze", "like_count": 0, "published_at": "2021-12-24T00:59:16Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgzgXl3m3p8o7LhZqh14AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\r\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-01-23T02:40:51Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "Ugx-sSEW5lPJ2iG2UHR4AaABAg", "text": "In Woodbridge, we are representing owners in the leasing of a beautiful 4 bedroom, single family home at 70 Summerstone. Very nice upgrades, spacious backyard:  love living in Woodbridge by leasing 70 Summerstone!\n\nhttps://www.bruceclarkgroup.com/listing-detail/1170134714/70-Summerstone-Irvine-CA\n\n#woodbridgeirvine #bruceclark #realbroker #homeforlease", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-10-02T00:35:11Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "UgzLnuQixuClgf6K8h14AaABAg", "text": "We love Irvine and Woodbridge has so many great things to offer residents. As of 10/1/2025, we have two properties available in Woodbridge:  43 Glenhurst, which is being offered for sale or for lease. A very nicely-upgraded 3 bedroom condo.\n\nhttps://www.bruceclarkgroup.com/listing-detail/1166293290/43-Glenhurst-Irvine-CA\n\n#IrvineCondo #condoforlease #irvinerealestate #woodbridge", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-10-02T00:32:09Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "UgyzvNMSHouK_hW5Zv14AaABAg", "text": "I live in Woodbridge and I love it \u2764", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T17:45:54Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "Ugx2VECQkM-XCyCtoch4AaABAg", "text": "Really loving your videoss so amazing keep it up \ud83e\udd0d\ud83e\udd0d", "author": "@pankaj_suman", "like_count": 0, "published_at": "2024-01-19T08:01:59Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgyajVeqSVcNXNsjH0F4AaABAg", "text": "great editing btw", "author": "@lysssky2", "like_count": 0, "published_at": "2023-06-12T05:27:18Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "Ugw0Qh4EZBmLNeWJ9wN4AaABAg", "text": "the homes look older", "author": "@lysssky2", "like_count": 0, "published_at": "2023-06-12T05:25:57Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg", "text": "I love your driving tours!", "author": "@kaleimaile", "like_count": 1, "published_at": "2023-06-11T00:36:29Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qo2CBl68Hg", "text": "Thanks! We''re doing a lot more!", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-06-11T04:22:15Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qo4WnulXg5", "text": "@LivinginOrangeCounty , Whoohoo!  While you guys talk about the various streets, I try to figure where you\u2019re at from the maps on my phone. Lol!  Do a driving tour in FV or HB & I will know where you are driving to in the video! \ud83d\ude02\ud83e\udd23\ud83d\ude02", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-06-11T04:42:32Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qp2b_7FWhE", "text": "@kaleimaile Lol. We are definitely planning a driving tour of FV and HB. It''s just been so overcast we''re waiting for the skies to clear, lol.", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-06-11T13:45:05Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qp42lTvhQ6", "text": "@LivinginOrangeCounty , hehe. Thanks. I know. It\u2019s been overcast, but I love the weather for running. I am not looking forward to having a hot summer. \ud83e\udd75\ud83e\udd75\ud83e\udd75", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-06-11T13:57:41Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qpwhEfOimk", "text": "@56strine , oh, but the \u2018runner\u2019s high\u2019 is why we run long distance. Lol!", "author": "@kaleimaile", "like_count": 1, "published_at": "2023-06-11T22:03:56Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzIynuECI4cDcXOyPZ4AaABAg", "text": "I live in Woodbridge and love it\ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T00:13:38Z", "parent_id": null, "video_id": "HGAaEys0P1w"}, {"id": "UgxCms6_rQcf52rs4i94AaABAg", "text": "I spent middle and high school in this commie-munity. California is already wildly expensive and restrictive, but have your minds blown with HOA Karens and violation letters\u2026 \ud83e\udd26\ud83c\udffb\u200d\u2642\ufe0f", "author": "@SNAKEEATER1776", "like_count": 0, "published_at": "2025-04-22T12:54:48Z", "parent_id": null, "video_id": "HGAaEys0P1w"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('university-town-center', '2026-04-29 05:41:28.071523', 3400.2223362668137, NULL, NULL, NULL, 0.319, 89.23, 2.48, 84.26, 68.0, 75.0, '["NitCpMg3RTE", "wDzbxwCvwnA", "ReuCsIZgXkI", "3lep-Ui5FxE", "2Z_NzK00lSg", "a-erhfkqTi4", "-H1L4lrwlso", "Nz2VCPxuVes", "kOOtA8Snjx0"]', '[{"id": "UgzCBXPqsZIdvSshzi54AaABAg", "text": "glamour piece. useless.", "author": "@forwags", "like_count": 0, "published_at": "2026-04-08T19:16:27Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}, {"id": "UgxEfq1naB6XwvVgDF94AaABAg", "text": "Comment on which campus you''d like to see next", "author": "@MathTeddyLofi", "like_count": 0, "published_at": "2023-04-13T02:16:16Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}, {"id": "UgwCvDsgAh-Y4b7Zcz14AaABAg", "text": "We finally get an Irvine video", "author": "@melvinchen7051", "like_count": 1, "published_at": "2023-04-12T17:16:49Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}, {"id": "UgxqPrnMXEbOW_OEnC54AaABAg", "text": "Brought and PAID for by UCI. \ud83d\ude02", "author": "@maximai", "like_count": 0, "published_at": "2026-04-03T04:28:49Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "Ugy4IXepHpvfztTf5uN4AaABAg", "text": "UCI is the biggest commuter school \u2620\ufe0f", "author": "@electrongaming123", "like_count": 3, "published_at": "2025-09-29T18:43:44Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "Ugwl2fYNyqduKPBjcJp4AaABAg", "text": "UCI does not have a social life \ud83d\ude05", "author": "@Lakan-dula", "like_count": 26, "published_at": "2025-09-15T15:42:05Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgwYPMQN_FTzqwmBF8h4AaABAg", "text": "I got into UCI :)", "author": "@mr.fishstick_yt9955", "like_count": 5, "published_at": "2024-03-22T04:19:33Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgxQBgFHtWFpyiW_FB54AaABAg", "text": "UCI \u2764", "author": "@sunflowersarles1sun827", "like_count": 2, "published_at": "2023-10-13T01:38:47Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgyxF3ZDGljG0FvytDl4AaABAg", "text": "Did you get into one of them ?", "author": "@doucegraciela5555", "like_count": 1, "published_at": "2022-10-09T05:28:37Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "Ugy-BjL9VuIZOWwUEl14AaABAg", "text": "\u7559\u5b66\u751f\u306fArroyo Vista\u304c\u5927\u534a\u3068\u805e\u304d\u307e\u3057\u305f\u3002\u305d\u3053\u4ee5\u5916\u306e\u5bee\u306b\u7559\u5b66\u751f\u306f\u4f4f\u3093\u3067\u3044\u307e\u3059\u304b\uff1f\u307e\u305f\u3001\u4ed6\u306e\u5bee\u3060\u3068\u7559\u5b66\u751f\u304c\u5c11\u306a\u304f\u3066\u8f9b\u3044\u601d\u3044\u3092\u3059\u308b\u3053\u3068\u306f\u3042\u308a\u307e\u3059\u304b\uff1f", "author": "@\u305f\u3053-r9x1q", "like_count": 0, "published_at": "2024-07-28T16:34:54Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugwgx2WHOSrfo0MT0N94AaABAg", "text": "Camino Del Sol is the safer place to live? :-/   Why isn''t the other place safe too?", "author": "@lisan1823", "like_count": 0, "published_at": "2023-09-21T06:03:49Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugwgx2WHOSrfo0MT0N94AaABAg.9uuruM-AYdh9uwFVrcJXPm", "text": "Hi there, Irvine is generally pretty safe! Camino Del Sol is a smaller community and is closer to campus/other housing than Vista Del Campo and Vista Del Campo Norte, so there is more traffic and events happening regularly. Vista Del Campo is on the outskirts of campus so there is minimal traffic/activity happening in that area but some of my friends who lived in that area enjoyed it. What was sometimes challenging was how far it was from campus.", "author": "@a2fIrvine", "like_count": 2, "published_at": "2023-09-21T18:58:02Z", "parent_id": "Ugwgx2WHOSrfo0MT0N94AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "Ugwlj3KmqBbSiogrvXh4AaABAg", "text": "I actually live near here and go to uni high school I walk around up I from time to time near the Main Street so I know the area pretty well", "author": "@strangerthingsfan4521", "like_count": 0, "published_at": "2022-05-24T02:29:51Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugy-3Enzl44diTnMgBh4AaABAg", "text": "I\u2019m not sure if you guys answer anymore but in terms of cost do you guys recommend ACC or UTC? I\u2019m going to be a transfer soon and this whole housing process have been giving me headaches. Also do any of the options allow non-students to temporarily live with you for a while like for a visit?", "author": "@user-kx1cy3re6k", "like_count": 3, "published_at": "2022-05-20T14:23:34Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugy-3Enzl44diTnMgBh4AaABAg.9bFcNn0SyB79bFcfE9gMuK", "text": "Also do I have to have a roommate or is there options otherwise?", "author": "@user-kx1cy3re6k", "like_count": 1, "published_at": "2022-05-20T14:26:05Z", "parent_id": "Ugy-3Enzl44diTnMgBh4AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "UgxjJwZyUU_4VNxY5vF4AaABAg", "text": "Hi , I am Namgyal and lives in New York , this summer I got accepted into a research program at UCI and I am looking for a room for a 10 weeks . So any leads on such will be highly appreciated. Thank you", "author": "@namgyaldolma2098", "like_count": 0, "published_at": "2022-03-31T12:58:01Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "UgxjJwZyUU_4VNxY5vF4AaABAg.9_EiqQreOsG9asZnwV-har", "text": "One pointer is the people subleasing their rooms for summer, for the ACC apartments, since the lease is 12 months long and not everyone is staying for the summer. Another pointer would be summer housing at the various on-campus housing communities, including dorms, though I''m not sure on the specifics", "author": "@_DeathDreams_", "like_count": 0, "published_at": "2022-05-11T06:10:33Z", "parent_id": "UgxjJwZyUU_4VNxY5vF4AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "UgxRKb6iTwavcDuRqCR4AaABAg", "text": "Very good and funny videos bring a great sense of entertainment!", "author": "@PhuongNguyen-se7xd", "like_count": 0, "published_at": "2021-10-25T08:49:11Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "UgyGVkU9iMq3hM_ZBLN4AaABAg", "text": "Most nicest?!?!?!? No!! No!!! Noooooooooo. Lol", "author": "@ellenlewitt", "like_count": 0, "published_at": "2021-08-12T22:07:49Z", "parent_id": null, "video_id": "-H1L4lrwlso"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('northwood', '2026-04-29 05:42:01.280047', 3400.2223362668137, NULL, NULL, NULL, 0.037, 74.0, 2.48, 83.44, 68.0, 75.0, '["5tu2lcRB-RU", "pvb2y-q8-c8", "1sKUs9DxK7I", "boT5DROWr0Q", "MZ_ZFTJJ9X0", "w9M-tKdSUYc", "4G89kNeLjNM", "OcrZoj7p1V4", "lodJQ9yhhuI"]', '[{"id": "Ugw_QwjGyXF1MwbxkYB4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-09-21T03:58:39Z", "parent_id": null, "video_id": "pvb2y-q8-c8"}, {"id": "Ugx7J4ApIRFQ9ve10F54AaABAg", "text": "======\nFull Channel:   https://bit.ly/3NXecX3\n======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-10-17T05:42:33Z", "parent_id": null, "video_id": "1sKUs9DxK7I"}, {"id": "UgxEzJNEdnCyA4AaCMJ4AaABAg", "text": "11:14 The house where Janelle Cruz was killed by the Golden State Killer RIP", "author": "@JesusGarcia-kl3rf", "like_count": 0, "published_at": "2026-02-16T21:35:45Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx-HS5Gi1lF2f8oodB4AaABAg", "text": "Thanks for the amazing information. From UK London", "author": "@jdxaofficial", "like_count": 1, "published_at": "2025-12-03T20:12:52Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgztpdqR7Fa8IVIC-894AaABAg", "text": "Anyone looking for a new or newer built home in Irvine, especially in the newer neighborhoods, you better be prepared to pay north of $2.0MM for an average size home.  Considering you will be assessed property taxes at the market value of the home along with two HOAs, even if you have $1.0MM to put as down payment, your monthly bill for all of the above will still be a boat load ! ! !\n\nSo a professional couple pulling in $400K/yr probably can swing this neighborhood. \n\nTraffic has beome a nightmare and people are driving like there is no tomorrow. With all the foreigners coming here and not know the traffic laws, you better have eyes on the back of your head!\n\nI spoke with an officer from the Irvine PD about the traffic and he said there isn''t much they can do unless there is an incident. So until someone smashes into your vehicle, don''t look for help from the Irvine PD ! ! !\n\nLastly, this is a master planned community and Irivne being a DEI community, they have painted huge portions of the roadway for bicycles ! ! !  This encroaches on roadways for normal traffic!  I never ever see any bicycles on these marked off portion fo the roads but that''s Irvine putting taxpayers'' money to waste!", "author": "@LWRC", "like_count": 1, "published_at": "2024-08-26T23:49:04Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgxLYOC0IqIKn8mIfVx4AaABAg", "text": "Gr\u00fcne Welle (Green Wave Traffic lights) like germany", "author": "@dr.mirano", "like_count": 0, "published_at": "2023-06-08T04:29:16Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgzE9hZpLHws9Wo6U854AaABAg", "text": "Thank you for being the spokespersons for irvine", "author": "@afterburner5560", "like_count": 0, "published_at": "2023-05-28T06:44:32Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg", "text": "Nice!  When I am in the market for a condo, I will call you. Are there condo\u2019s that aren\u2019t HOA\u2019s in HB or Costa Mesa?", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:25:18Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHV-OcIY5", "text": "HI Kalei ! \nThere aren''t any condos that I''m aware of that have no HOAs.  The reason being is that condos have shared walls, fences, etc.  The HOA dues can definitely vary from one community to the next.  When you are ready to reach out, we can go over all of different aspects of the various HOAs, including their HOA dues.", "author": "@runbamrun", "like_count": 1, "published_at": "2023-05-27T21:43:59Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHye9laNE", "text": "@runbamrun , I need prices to go down before I could afford a house.", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:48:10Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('costa-mesa-border', '2026-04-29 05:42:35.308563', 3088.072448466566, NULL, NULL, NULL, 0.527, 279.05, 4.23, 85.27, 75.0, 82.0, '["aMoiKj7tEPI", "9jdBAgf77nw", "LzyeK1zb9_4", "jS5F_g_esjI", "R2zJ73ccgfk", "VhvlsJunOUQ", "qq7DUUW658A", "YmfLYoVM5FM", "6C8M4QtFrBU"]', '[{"id": "Ugxq0nvhV951PP8t_6t4AaABAg", "text": "Yesterday, Glimmerito tried to shoot a 30-year-old woman \ud83d\udc69 after trying to replace my music \ud83c\udfb6 therapist after I attacked and nearly put an end to her.", "author": "@emily91303", "like_count": 0, "published_at": "2023-08-03T09:19:09Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzVSt4kU9HLIexEAM94AaABAg", "text": "If you wouldnt of broke the law coming here illegally in the first place you wouldnt be dead. \ud83d\ude02\ud83d\ude02\ud83d\ude02\ud83d\ude02.. try and play victim.", "author": "@travisengland1368", "like_count": 0, "published_at": "2023-07-17T00:46:45Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "Ugw_t3DfLVwLJKBV5SN4AaABAg", "text": "Well maybe if they didnt hit a car with a family in it and then drive away they wouldnt of got shot.. good job lee. You da man Stay up g..", "author": "@travisengland1368", "like_count": 0, "published_at": "2023-07-17T00:45:04Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgxdFaVdHwU-w4qjI5x4AaABAg", "text": "Export this criminal activity back to Mexico", "author": "@OLD-GUY-99", "like_count": 0, "published_at": "2023-07-05T01:24:34Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgwjzbiuxhUPAJ13u9Z4AaABAg", "text": "Foo struck out big time.... No more Woman, vacations \ud83c\udfdd\ufe0f,  steak \ud83e\udd69, shrimp \ud83c\udf64, ocean \ud83c\udf0a,  .... Was it really worth it????? Nothing but showers \ud83d\udebf with naked men all around u for the rest of ur young life...... Gotta think \ud83e\udd14 before u react.... It''s hard, but it''s a must!!!!", "author": "@simonrangel9522", "like_count": 0, "published_at": "2023-02-22T04:28:24Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzanZrq_cAX8LQMPOx4AaABAg", "text": "More to the story for sure.", "author": "@mikelabree", "like_count": 0, "published_at": "2023-01-31T03:17:23Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgwO0S1vIVsrTNbN4bx4AaABAg", "text": "Rest in peace of my Dad''s friend he''s been a wonderful person and we pray God that he''s going to be okay this is the fake this is real this is what''s my dad''s friend", "author": "@abandoned_dead", "like_count": 1, "published_at": "2022-12-30T02:36:05Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzPeKb6lylDrKCosOh4AaABAg", "text": "Hmmmm, just a guess, black?", "author": "@peridoteyes3728", "like_count": 0, "published_at": "2022-12-11T23:12:03Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgyQZ0PEQhP-en1-wSp4AaABAg", "text": "I drive a truck I\u2019m always ready to defend if some punk tries to pull out a gun on me.", "author": "@ezpe3865", "like_count": 0, "published_at": "2022-12-11T02:19:41Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "Ugw-OCIiL7potSaPLS94AaABAg", "text": "Why didn\u2019t you guys show the shooters picture \ud83e\udd26", "author": "@DirtyDrifter", "like_count": 0, "published_at": "2022-12-11T01:17:04Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgxCWUT9f8PCtBGp4H54AaABAg", "text": "I didn''t see a shark attack her,and I''m glad I didn''t. I was praying \ud83d\ude1e\ud83d\ude4f", "author": "@IsayswhatIsays_91", "like_count": 0, "published_at": "2026-04-09T19:20:32Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxaA7s5drIkpnhwqKB4AaABAg", "text": "silly waste of your time and mine\ud83e\udd2c\ud83e\udd2f\u2757\ufe0f", "author": "@giglambert8787", "like_count": 0, "published_at": "2026-04-02T19:45:08Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxjcyJnm-xD9_TS2Pt4AaABAg", "text": "Shark!!! Maybe a beaver attack with a full moon????\ud83d\ude0a\ud83d\ude0a\ud83d\ude0a\ud83d\ude0a", "author": "@j.e.g2321", "like_count": 0, "published_at": "2026-03-29T04:38:07Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "Ugx0czskOGIW_jkr5Nl4AaABAg", "text": "Looks like shes pi$$ing", "author": "@briandonahue3663", "like_count": 0, "published_at": "2026-03-28T19:04:41Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxOWlpXvQlt1fAduxx4AaABAg", "text": "Don''t take the sharpy find a leg or he won''t stop the headstones from brote", "author": "@mis-u2y", "like_count": 0, "published_at": "2026-03-27T23:24:37Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgzJm_d-piXAm-Mpft14AaABAg", "text": "That hungry butt must have ate the shark. It was devouring the swimsuit for dessert.", "author": "@cobrakaiX", "like_count": 0, "published_at": "2026-03-27T14:53:45Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgwR9yqwX3IEZR02eSp4AaABAg", "text": "What shark? The seagull?", "author": "@Bobbyboy-i3z", "like_count": 0, "published_at": "2026-03-18T19:03:17Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgyrMS77lojHk-CH_a14AaABAg", "text": "The shark ate your baby...\nAnd now you are wearing her swimsuit.", "author": "@diasdesmo1730", "like_count": 0, "published_at": "2026-03-07T17:47:32Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgzGfjqJRWeF1YdCb0h4AaABAg", "text": "Two years later, the clickbait still works!", "author": "@Guu1969", "like_count": 0, "published_at": "2026-03-04T19:49:28Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgyFAr0gQe2iibCaEPV4AaABAg", "text": "B.S.", "author": "@THENEONARCADE21", "like_count": 0, "published_at": "2026-02-22T05:14:50Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg", "text": "Get a $100 Amazon Gift Card when you use PODS: https://tailhappytv.com/pods-100-amazon-gift-card (super simple)\nPlease consider clicking the \"super thanks\" heart button to help support my channel! \nMoving Boxes: https://amzn.to/3h3Voo3\nRatchet straps: https://amzn.to/2Wl8s0I\nFurniture wrap: https://amzn.to/30a0gBH\nMattress bag: https://amzn.to/3esoagY\n\nNeed help moving heavy stuff? Watch my other video: http://youtu.be/AkK62JD8q8U\n\nMoving Blankets: https://amzn.to/3jCamTY\n\nGet a Free Moving Quote from U PACK before you commit to PODS: http://bit.ly/freemovingquote2", "author": "@TailHappyTV", "like_count": 52, "published_at": "2020-09-02T15:42:29Z", "parent_id": null, "video_id": "qq7DUUW658A"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg.9D6R_tteoY39_gDAjARkA-", "text": "thanks for this video... definitely answered some of my questions!", "author": "@RedAlEarttDramaMeanWhoDat", "like_count": 0, "published_at": "2022-04-11T14:30:33Z", "parent_id": "UgxxAJTAA4BTjhT23St4AaABAg", "video_id": "qq7DUUW658A"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg.9D6R_tteoY39cexvU0XIwB", "text": "I used your \"Super Thanks\" feature \ud83d\udcb0", "author": "@sunnydays3476", "like_count": 0, "published_at": "2022-06-24T16:23:27Z", "parent_id": "UgxxAJTAA4BTjhT23St4AaABAg", "video_id": "qq7DUUW658A"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg.9D6R_tteoY39cey4zVIeq5", "text": "Wow! Thank you SO MUCH! I appreciate you!", "author": "@TailHappyTV", "like_count": 0, "published_at": "2022-06-24T16:24:53Z", "parent_id": "UgxxAJTAA4BTjhT23St4AaABAg", "video_id": "qq7DUUW658A"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg.9D6R_tteoY39em3fqMFxfJ", "text": "I am curious to know how your MOVE OUT of CALIFORNIA went...", "author": "@allwaizeright9705", "like_count": 1, "published_at": "2022-08-16T03:39:58Z", "parent_id": "UgxxAJTAA4BTjhT23St4AaABAg", "video_id": "qq7DUUW658A"}, {"id": "UgxxAJTAA4BTjhT23St4AaABAg.9D6R_tteoY39em3zHYtmi9", "text": "@allwaizeright9705 I\u2019ll let ya know if I leave :)", "author": "@TailHappyTV", "like_count": 1, "published_at": "2022-08-16T03:42:37Z", "parent_id": "UgxxAJTAA4BTjhT23St4AaABAg", "video_id": "qq7DUUW658A"}, {"id": "UgzLEgQQFGE70Wv1Utt4AaABAg", "text": "just like all of your videos.. great video.. you must have moved again because all of your ebike videos seam to be at a different location..", "author": "@darinsmith2458", "like_count": 0, "published_at": "2026-04-27T04:36:11Z", "parent_id": null, "video_id": "qq7DUUW658A"}, {"id": "UgyeFqhNaIJPcD6yuVZ4AaABAg", "text": "You made My Day", "author": "@DennisLyon-v4q", "like_count": 0, "published_at": "2026-04-17T20:15:29Z", "parent_id": null, "video_id": "qq7DUUW658A"}, {"id": "UgyjHbzvIdHBoUXSFKB4AaABAg", "text": "Their price has doubled now in 2026, the 7ft pod now was quoted at $3900. Ridiculous", "author": "@fishes74", "like_count": 0, "published_at": "2026-04-13T18:18:21Z", "parent_id": null, "video_id": "qq7DUUW658A"}, {"id": "UgwjdQtyYNnmyCDS60x4AaABAg", "text": "The charge for that mileage was very expensive.", "author": "@michaelfishman7174", "like_count": 0, "published_at": "2026-02-23T05:34:41Z", "parent_id": null, "video_id": "qq7DUUW658A"}, {"id": "UgzVgp7rUSiKHkVbpOx4AaABAg", "text": "I plan to have two bottles of extra strength Tylenol bedside at all times.  Death is not painful, it is like going to sleep.", "author": "@cecilbatts8835", "like_count": 1, "published_at": "2026-04-19T23:40:10Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgxDTWK5P0cIpWiDQOV4AaABAg", "text": "$12,000 a month in Washington state.", "author": "@LilyGazou", "like_count": 0, "published_at": "2026-04-15T01:18:51Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "Ugx1oPvrpgbtfw9F--R4AaABAg", "text": "Yeah, spend all your $, don''t save and let medicaid pay for it!! And put your home in irrevocable trust 5 yrs before going to nsg hm or assistive living. If not, that goes to facility. It''s a SCAM!", "author": "@SusanFisher-e9u", "like_count": 0, "published_at": "2026-04-07T12:05:00Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "Ugxgzei7HOzhLXuc38d4AaABAg", "text": "\ud83d\udc94\ud83d\ude2d", "author": "@teriliebmann3491", "like_count": 0, "published_at": "2026-04-05T05:28:13Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "Ugz76yKm5JqAHDPCodp4AaABAg", "text": "43k  a month 51k a year???? What???", "author": "@tinapizarro-henderson4066", "like_count": 0, "published_at": "2026-04-02T13:51:01Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgwW1IAJ8MQocFKd5mt4AaABAg", "text": "For profit facilities have no soul ! Taking care of our elderly and disabled should not be managed by greedy for profit companies!", "author": "@Lyn45688", "like_count": 0, "published_at": "2026-03-23T07:52:27Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgzEJIQk_kZSnK2ECxh4AaABAg", "text": "I would rather be dead.", "author": "@lynnmarie1381", "like_count": 0, "published_at": "2026-03-23T00:04:56Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgzySLoha4kmvOWYKyx4AaABAg", "text": "43k a month?", "author": "@Biscuit9891", "like_count": 0, "published_at": "2026-03-21T23:12:39Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgzhQUriqFrOYiB9JLl4AaABAg", "text": "$43,000/month LOL feels like it!", "author": "@aaronvegh3034", "like_count": 0, "published_at": "2026-03-21T02:27:55Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}, {"id": "UgxaNgj8IJjQ2kzGeVt4AaABAg", "text": "And so-called long-term care insurance won''t pay without you lawyering up.    Look into it.   Personally, my idea is to stop eating and drinking when I can''t take care of myself.   I want to have a paper drawn up that says not to feed me if I cannot feed myself.", "author": "@silverhausen", "like_count": 0, "published_at": "2026-03-19T17:55:33Z", "parent_id": null, "video_id": "6C8M4QtFrBU"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('great-park', '2026-04-29 05:43:23.301694', 3400.2223362668137, NULL, NULL, NULL, 0.0, 72.0, 2.48, 87.1, 62.0, 69.0, '["5tu2lcRB-RU", "7iLH9vzL2Qo", "mzUJlvPVEIU", "BCi20EOGAOw", "6YgL4JN1bYw", "fgnmivjjM5Y", "wbW7ATTytGw", "lodJQ9yhhuI"]', '[{"id": "UgxoJCWe8ALUYknsCbh4AaABAg", "text": "is it true that Great Park is was the former El Toro Marine Corps Air Station which is a toxic Superfund site?? i want to move here but this is a huge community concern if it''s true", "author": "@sp-ff1pt", "like_count": 0, "published_at": "2025-12-06T18:09:20Z", "parent_id": null, "video_id": "mzUJlvPVEIU"}, {"id": "UgyS-5UXKpCisyHaCB14AaABAg", "text": "The Ducks train there (Irvine) but all Home games ( where the play) are at the Honda Center. Nice video.", "author": "@sikhlion5325", "like_count": 0, "published_at": "2026-01-21T02:05:18Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgwK87YbpQYZA1botKV4AaABAg", "text": "WOW", "author": "@kennaylul", "like_count": 1, "published_at": "2025-04-06T23:56:14Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgxdHUhUk6rXtNb2iRF4AaABAg", "text": "Hi There,\r\nHow are you?\r\nI watched your videos, and your video quality is great! However, your videos are not properly optimized for SEO. Your SEO score is quite poor, which is why your channel is not growing organically.\r\nSEO stands for Search Engine Optimization. I\u2019m sure you understand that to get more views, subscribers, and comments, your videos need to rank higher on YouTube. Proper SEO, such as selecting low-competition keywords, can help your channel rank at the top.\r\nThank you", "author": "@Mrjosef-m6i", "like_count": 1, "published_at": "2025-04-06T18:02:47Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgzF1rBsIfGC1fxKAQB4AaABAg", "text": "\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764", "author": "@ThienPham-bj9ki", "like_count": 1, "published_at": "2025-04-05T22:54:15Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgybCfVKLxz429TY-Gd4AaABAg", "text": "When is it gonna be made?", "author": "@Kyson-p8c", "like_count": 0, "published_at": "2026-03-11T19:16:52Z", "parent_id": null, "video_id": "fgnmivjjM5Y"}, {"id": "UgxuakSkH-9yNOFW2pt4AaABAg", "text": "As of today, pretty much 1 M or above in GP.", "author": "@jennifer12366", "like_count": 1, "published_at": "2025-05-29T22:15:02Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgxuakSkH-9yNOFW2pt4AaABAg.AIikijwDg1JAIjO4EPAvkz", "text": "Thanks for watching our video! It''s Irvine so that sums up the market...However, if looking for a new home, builders are being very aggressive with offering incentives on upgrades and financing. Still not inexpensive though!", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-05-30T04:07:38Z", "parent_id": "UgxuakSkH-9yNOFW2pt4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "text": "Like like like like like like", "author": "@Yuriy_Beskrovniy", "like_count": 1, "published_at": "2023-03-24T16:56:35Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg.9ndyiur43ex9ne31aT96tR", "text": "Thanks Thanks Thanks! Really appreciate your watching our videos.", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-03-24T17:42:57Z", "parent_id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "Ugy-WHOhohgo7cO0omh4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-08-21T03:57:15Z", "parent_id": null, "video_id": "wbW7ATTytGw"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('stonegate', '2026-04-29 05:48:30.835965', 3400.2223362668137, NULL, NULL, NULL, 0.061, 75.29, 2.48, 81.02, 68.0, 75.0, '["_cojvvo6JN8", "rElx4jAI6lE", "0bXkDN2JD3o", "bbesnMizEAU", "wDzbxwCvwnA", "BFjN3i09j2I", "mDqwTT_WOoc", "jb2-VPl-rao", "6d2xUJRJejs", "CDMR4CWG4sw", "rQnl3wVdMtk", "Dl5KI5OBlAs"]', '[{"id": "UgyPTLc_t0QK9dkKMGN4AaABAg", "text": "Irvine is a wonderful place to live. Parts of it have become very crowded however.", "author": "@Slion18", "like_count": 1, "published_at": "2025-08-02T17:42:22Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "UgyPTLc_t0QK9dkKMGN4AaABAg.ALKdBX_3XpUALjiVEvNijg", "text": "Absolutely! Irvine has so much to offer with its schools, safety, and community vibe, but you\u2019re right, some areas have become more crowded in recent years. It\u2019s something I often talk about with clients so they can find the neighborhood that best fits their lifestyle.", "author": "@ReginaChenRealtor", "like_count": 0, "published_at": "2025-08-12T20:49:00Z", "parent_id": "UgyPTLc_t0QK9dkKMGN4AaABAg", "video_id": "BFjN3i09j2I"}, {"id": "UgyjI2vtYeZEpCMsEwh4AaABAg", "text": "Regina, love your video, super informative!", "author": "@davidlu5356", "like_count": 0, "published_at": "2023-02-24T17:44:30Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "UgyjI2vtYeZEpCMsEwh4AaABAg.9mWxxQKIF5O9mXFnsoH9Ol", "text": "Thanks, David. Glad to hear that it''s helpful. Let me know anything else you want to know or see about Irvine\ud83d\ude42", "author": "@ReginaChenRealtor", "like_count": 0, "published_at": "2023-02-24T20:29:13Z", "parent_id": "UgyjI2vtYeZEpCMsEwh4AaABAg", "video_id": "BFjN3i09j2I"}, {"id": "UgzUdUWd9P_X6Yburvx4AaABAg", "text": "greate intro video to irvine homes that I can find on youtube", "author": "@tonydong13", "like_count": 1, "published_at": "2022-12-28T06:16:45Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "UgzUdUWd9P_X6Yburvx4AaABAg.9kAO8PFBS-j9kslrJ5v2M6", "text": "Glad it was helpful!", "author": "@ReginaChenRealtor", "like_count": 0, "published_at": "2023-01-14T21:18:33Z", "parent_id": "UgzUdUWd9P_X6Yburvx4AaABAg", "video_id": "BFjN3i09j2I"}, {"id": "UgzDuf6gvy8VR-9hz414AaABAg", "text": "BAD VIDEO.. NO PICTURES...!! YOU ARE A LAZY REAL ESTATE AGENT!!", "author": "@Malefabulous", "like_count": 1, "published_at": "2022-10-14T04:02:51Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "UgzpTDmhwW4YRvItg4l4AaABAg", "text": "What is single family homes?", "author": "@hk70s48", "like_count": 0, "published_at": "2022-03-12T02:22:45Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "Ugy1NbwpCi8etn3PpTh4AaABAg", "text": "Nice \ud83d\udc4d video! Subscribed! Nice to find another YouTuber here! Very rare! Welcome!", "author": "@marcoreviews", "like_count": 1, "published_at": "2022-01-20T04:28:19Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "Ugz2dZ0cBrIDL2O48bt4AaABAg", "text": "Music is dominating your voice. Why do you want it when you are talking", "author": "@parimalaswathi6444", "like_count": 1, "published_at": "2021-10-11T21:31:03Z", "parent_id": null, "video_id": "BFjN3i09j2I"}, {"id": "Ugxb7KYJoLPWgALiAJF4AaABAg", "text": "\u8fd9\u5957\u8fd8\u5728\u552e\u4e2d\u5417\uff1f", "author": "@maguro001", "like_count": 0, "published_at": "2022-10-20T21:03:23Z", "parent_id": null, "video_id": "6d2xUJRJejs"}, {"id": "Ugxb7KYJoLPWgALiAJF4AaABAg.9hQIl-Z9FBx9hQKW1eBTC-", "text": "156\u4e07\u552e\u51fa\u4e86", "author": "@cocoyuteam", "like_count": 0, "published_at": "2022-10-20T21:18:41Z", "parent_id": "Ugxb7KYJoLPWgALiAJF4AaABAg", "video_id": "6d2xUJRJejs"}, {"id": "Ugxb7KYJoLPWgALiAJF4AaABAg.9hQIl-Z9FBx9hQKnPIMh3X", "text": "@cocoyuteam \u77e5\u9053\u4e86\uff0c\u8c22\u8c22", "author": "@maguro001", "like_count": 0, "published_at": "2022-10-20T21:21:11Z", "parent_id": "Ugxb7KYJoLPWgALiAJF4AaABAg", "video_id": "6d2xUJRJejs"}, {"id": "UgxgWUTIbF642ufiFBx4AaABAg", "text": "The cons is it\u2019s over built and the traffic is horrible!", "author": "@MikeB-in1nd", "like_count": 2, "published_at": "2025-08-25T23:17:30Z", "parent_id": null, "video_id": "CDMR4CWG4sw"}, {"id": "UgxgWUTIbF642ufiFBx4AaABAg.AMGSpHf6c0DAMOtuUr-n5e", "text": "Yet the building keeps happening and people keep coming.", "author": "@MoveToOrangeCounty", "like_count": 1, "published_at": "2025-08-29T05:56:48Z", "parent_id": "UgxgWUTIbF642ufiFBx4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgxgWUTIbF642ufiFBx4AaABAg.AMGSpHf6c0DANCRUrQO-Cm", "text": "Traffic is everywhere. If you don\u2019t like traffic you can go to idk like Alabama or Montana lol", "author": "@LEMONSTERPLAYSPUBG", "like_count": 0, "published_at": "2025-09-18T06:20:17Z", "parent_id": "UgxgWUTIbF642ufiFBx4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg", "text": "There are a lot of restaurants in Irvine, however there''s no Ding Tai Fung there.  The Ding Tai Fung shown in the video is actually located at Disney Downtown in Anaheim.  There''s another one nearby at the South Coast Plaza mall in Costa Mesa.", "author": "@tedc2158", "like_count": 1, "published_at": "2025-01-28T06:30:55Z", "parent_id": null, "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg.ADpVUt9N4UEADqNhbcupx8", "text": "I go to the one in south coast plaza! I should have said there\u2019s one Coming Soon to Spectrum center in Irvine! @tedc2158", "author": "@MoveToOrangeCounty", "like_count": 2, "published_at": "2025-01-28T14:42:07Z", "parent_id": "Ugwj06BTdq06mJHFaYV4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg.ADpVUt9N4UEADqOE3YvEQz", "text": "January 28, 2025", "author": "@MoveToOrangeCounty", "like_count": 0, "published_at": "2025-01-28T14:46:41Z", "parent_id": "Ugwj06BTdq06mJHFaYV4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg.ADpVUt9N4UEADqOLuAa_ef", "text": "@tedc2158 what\u2019s your favorite Irvine eatery? Do you have a favorite Italian spot by chance!?", "author": "@MoveToOrangeCounty", "like_count": 0, "published_at": "2025-01-28T14:47:45Z", "parent_id": "Ugwj06BTdq06mJHFaYV4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg.ADpVUt9N4UEADvUvWCVf20", "text": "@MoveToOrangeCounty My favorite was Sam Woo restaurant at the Culver Plaza but unfortunately they have closed.  Olive Garden is my favorite Italian.", "author": "@tedc2158", "like_count": 1, "published_at": "2025-01-30T14:21:23Z", "parent_id": "Ugwj06BTdq06mJHFaYV4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "Ugwj06BTdq06mJHFaYV4AaABAg.ADpVUt9N4UEADvVUAYj35n", "text": "@ You are right, there will be a Ding Tai Fung coming to the Irvine Spectrum. They already have it shown on the map for that shopping center as being located near the Nordstrom store.", "author": "@tedc2158", "like_count": 1, "published_at": "2025-01-30T14:26:15Z", "parent_id": "Ugwj06BTdq06mJHFaYV4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgzlexwLPXNx0o_srER4AaABAg", "text": "Irvine feels like the entire city is a convention.", "author": "@Pac-Lander", "like_count": 1, "published_at": "2025-01-14T08:40:10Z", "parent_id": null, "video_id": "CDMR4CWG4sw"}, {"id": "UgzlexwLPXNx0o_srER4AaABAg.ADGg9LhSVGEADHLfIV_P-J", "text": "What area of OC is your favorite?", "author": "@MoveToOrangeCounty", "like_count": 0, "published_at": "2025-01-14T14:51:40Z", "parent_id": "UgzlexwLPXNx0o_srER4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgzlexwLPXNx0o_srER4AaABAg.ADGg9LhSVGEADHLiuQjCfH", "text": "@pac-lander", "author": "@MoveToOrangeCounty", "like_count": 0, "published_at": "2025-01-14T14:52:10Z", "parent_id": "UgzlexwLPXNx0o_srER4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgzlexwLPXNx0o_srER4AaABAg.ADGg9LhSVGEADHhcWdNOr7", "text": "@  Not super familiar. I''ve spent the last 5 years in north county San Diego and love it, but considering moving closer to family (in Long Beach/Lakewood area), so I''ve been scouting out neighborhoods in OC. \n\nIrvine feels sort of devoid of character/vibe.\nSanta Ana is not for me.\nNewport and Laguna are nice. Not sure if it''s my scene though.\nHuntington Beach is cool, but seems super conservative. \nI am sort of looking at Costa Mesa as a possible spot. Trying to find somewhere close to nature/hiking, but also has a downtown hub and places to shop/eat/hang out/socialize.", "author": "@Pac-Lander", "like_count": 1, "published_at": "2025-01-14T18:12:16Z", "parent_id": "UgzlexwLPXNx0o_srER4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgzlexwLPXNx0o_srER4AaABAg.ADGg9LhSVGEADHopeTc6Lx", "text": "@Pac-Landerwe moved here from SD and are loving Costa Mesa! Reach out! 619-994-5437 \ud83d\ude0a", "author": "@MoveToOrangeCounty", "like_count": 0, "published_at": "2025-01-14T19:15:14Z", "parent_id": "UgzlexwLPXNx0o_srER4AaABAg", "video_id": "CDMR4CWG4sw"}, {"id": "UgzXVes_kNn2oddda3B4AaABAg", "text": "4) You don''t like to get ripped off doing errands", "author": "@hoaxnineteen", "like_count": 0, "published_at": "2026-04-24T19:27:08Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "text": "They lie about the safety in Irvine, I watched a couple flip their car and die on Alton, never made the news, kid recently died on his e-bike on keystone and regal, never makes the news or google search, no one can drive, we all know why\u2026", "author": "@SuperBaconFishing", "like_count": 3, "published_at": "2025-12-22T21:51:49Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg.AR2ibogH6dHAT-J0ogH1a-", "text": "Another reason is Chinese birth tourism, and nobody knows how to drive speak English", "author": "@IVvOOvVI", "like_count": 0, "published_at": "2026-02-09T07:04:30Z", "parent_id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "Ugyu5pjHyapyDRLQtpN4AaABAg", "text": "lol poor people reasoning... lol very simple, you can''t afford it, what a dumbass", "author": "@andrewstephen6493", "like_count": 0, "published_at": "2025-11-13T17:50:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugxu-xIJAOWTG9oOhQR4AaABAg", "text": "Buddy it\u2019s the safest country in the us", "author": "@Yoojian12", "like_count": 1, "published_at": "2025-10-06T22:46:04Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "UgwzBZLRpM9mDrGfTlJ4AaABAg", "text": "The elites need Californians to disapear or move away, thats theirs now.", "author": "@bmc9504", "like_count": 0, "published_at": "2024-05-22T20:41:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg", "text": "What''s up with the outfit, my guy \ud83d\ude02 I''m from Irvine so maybe don''t live here if ya hate it so much! \u2764", "author": "@kikilee7162", "like_count": 1, "published_at": "2024-05-22T19:36:24Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg.A3karJdRjfRA3kdlgWP805", "text": "Never said I hate it. \ud83d\ude0a", "author": "@LivingInIrvineCalif", "like_count": 0, "published_at": "2024-05-22T20:01:51Z", "parent_id": "Ugze1vj-7CZpBt9IEu94AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "UgxSQg0KVz7s-kVwDtR4AaABAg", "text": "U can keep that trash state", "author": "@pure_blood1", "like_count": 4, "published_at": "2024-05-22T15:45:33Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugzi_kMqXU1Iwoi_6754AaABAg", "text": "CA house and rental prices,gas price, grocery prices, restaurant prices,insurance costs,repair costs", "author": "@coletanner5193", "like_count": 2, "published_at": "2024-05-22T13:30:15Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "UgyR_nz0-YPHM6rzGNp4AaABAg", "text": "I live there\ud83d\udc80", "author": "@WtfJohead", "like_count": 2, "published_at": "2023-09-15T13:59:18Z", "parent_id": null, "video_id": "Dl5KI5OBlAs"}, {"id": "UgyR_nz0-YPHM6rzGNp4AaABAg.9ugGYXQ-Wm09uhXK8ezkDy", "text": "I love Stonegate!\nThank you for watching \ud83d\ude0a", "author": "@GMCBlvd", "like_count": 0, "published_at": "2023-09-16T01:45:07Z", "parent_id": "UgyR_nz0-YPHM6rzGNp4AaABAg", "video_id": "Dl5KI5OBlAs"}, {"id": "UgyPioUvw14M9roPckl4AaABAg", "text": "\ud83d\udc4d\ud83d\udc4d\ud83d\ude0d\ud83d\ude0d", "author": "@SA-yf1qy", "like_count": 2, "published_at": "2023-05-14T10:02:06Z", "parent_id": null, "video_id": "Dl5KI5OBlAs"}, {"id": "UgyPioUvw14M9roPckl4AaABAg.9pgYpjj3Ojx9pm5f9tKxWs", "text": "Thank you for watching \ud83d\ude07", "author": "@GMCBlvd", "like_count": 0, "published_at": "2023-05-16T13:42:41Z", "parent_id": "UgyPioUvw14M9roPckl4AaABAg", "video_id": "Dl5KI5OBlAs"}, {"id": "Ugys0AJwnKvoaNH_Rr54AaABAg", "text": "\ud83d\ude0aI from iraq", "author": "@compatsupzero9707", "like_count": 4, "published_at": "2023-05-14T07:01:01Z", "parent_id": null, "video_id": "Dl5KI5OBlAs"}, {"id": "Ugys0AJwnKvoaNH_Rr54AaABAg.9pgE6Tiq0Dw9pm5a3uiKxk", "text": "Thank you for watching \ud83d\ude0a", "author": "@GMCBlvd", "like_count": 2, "published_at": "2023-05-16T13:41:59Z", "parent_id": "Ugys0AJwnKvoaNH_Rr54AaABAg", "video_id": "Dl5KI5OBlAs"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('cypress-village', '2026-04-29 05:44:42.277933', 3400.2223362668137, NULL, NULL, NULL, 0.24, 84.96, 2.48, 80.24, 75.0, 82.0, '["rc2Xb27uiZY", "lCdRxxezyF8", "z_k5rTp67UA", "Kx8cI8r9WO8", "QU7TbSheG9Y", "jEOiyvf9GdQ", "X5kDOsVK-eM", "QxgW1NWIlwM"]', '[{"id": "Ugyd2hwqLMuoY233fJt4AaABAg", "text": "Shouldnt sit there with the neighbors windows looking right at you", "author": "@Cross-xm2fr", "like_count": 1, "published_at": "2025-05-14T14:21:21Z", "parent_id": null, "video_id": "jEOiyvf9GdQ"}, {"id": "Ugyd2hwqLMuoY233fJt4AaABAg.AI6HaEqsZmGAI7UjjKgAkm", "text": "Haha, didn\u2019t even think about it. They probably would have thought I was crazy talking to myself!!", "author": "@RyanSchulzeRealEstate", "like_count": 0, "published_at": "2025-05-15T01:35:29Z", "parent_id": "Ugyd2hwqLMuoY233fJt4AaABAg", "video_id": "jEOiyvf9GdQ"}, {"id": "Ugh-8eTjrUDs0ngCoAEC", "text": "Hi Fred my friend is interested to buy.", "author": "@Daniela-zt6st", "like_count": 0, "published_at": "2014-04-05T21:41:23Z", "parent_id": null, "video_id": "X5kDOsVK-eM"}, {"id": "UgjrpkOoqX5GYngCoAEC", "text": "http://youtu.be/X5kDOsVK-eM\n\nCypress Village is the newest village in Irvine California offering many great amenities in the heart of Orange County.\n\nhttp://bestocproperties.com/cypress-village-review-irvines-newest-community-fridays-fred/", "author": "@FredSed", "like_count": 0, "published_at": "2013-05-31T16:06:50Z", "parent_id": null, "video_id": "X5kDOsVK-eM"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('oak-creek', '2026-04-29 05:44:07.006702', 3400.2223362668137, NULL, NULL, NULL, 0.031, 73.67, 2.48, 80.72, 68.0, 75.0, '["wFh8YI9xEQw", "F08HtkKlBLQ", "f-4c3kNBm3M", "8HkRHp8ocOo", "-_0Nfgut_N0", "9OlRx5tSQnU", "urwBJvYOtx0", "OIobezbcUh0"]', '[{"id": "Ugyb2LEfUEpKEEbUFMd4AaABAg", "text": "There is no debate. This is a done deal. At this point could city  consider refusing the 50 acre park, thus possibly causing the Irvine company to pay for the open space requirement themselves. \u2049\ufe0f", "author": "@breezybird403", "like_count": 0, "published_at": "2026-04-25T03:11:40Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgwfWwo1oOdVQN0bc5x4AaABAg", "text": "Hello! I am a student from EDUBUS. EDUBUS is an educational center for students seeking admission to private schools. I am currently attending a class about this redevelopment. We will attend a City Council Meeting to try to persuade them to keep the Oak Creek Golf Course. As one of the scripters (potentially the speaker), I would dearly appreciate some opinions on this redevelopment.", "author": "@faltrx", "like_count": 0, "published_at": "2025-08-06T03:58:48Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgzcoU55MQ42fz6YB_F4AaABAg", "text": "Surely you have enough traffic already.", "author": "@chris7987", "like_count": 0, "published_at": "2025-07-09T03:52:14Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgyZ5IB8m3r0Rs02Lz14AaABAg", "text": "More expensive housing? Irvine is already for rich people \ud83d\ude02", "author": "@Chato829", "like_count": 0, "published_at": "2025-07-07T23:21:13Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgwHVeYpEdHRmxYDnEB4AaABAg", "text": "You know how cities work. If they want it, they''ll take it.", "author": "@slanphere4", "like_count": 2, "published_at": "2025-07-07T10:31:26Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgyQnpL6mnGR_ALppbx4AaABAg", "text": "Watching this video gave me hope in golf.", "author": "@user-vr6yw3tp7p", "like_count": 1, "published_at": "2024-01-24T20:50:40Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugwt3SYuFnQZMbGQ9A54AaABAg", "text": "I actually like the commentary over the top with some moments during the round shared.  Good perspective.  Also, you''re in my league so happy to see the coaching in the cart! lol  Keep up the great content.", "author": "@majen66", "like_count": 2, "published_at": "2023-11-15T23:51:30Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugwt3SYuFnQZMbGQ9A54AaABAg.9x9OoJdOIVB9x9Z8bfn9BV", "text": "I really appreciate feedback like this. I''m still trying to figure out my \"style\" of video and it''s really helpful to hear what viewers like as I try different things out. Thanks so much!! Appreciate your watch and your comments.", "author": "@golfwithjames", "like_count": 0, "published_at": "2023-11-16T01:21:47Z", "parent_id": "Ugwt3SYuFnQZMbGQ9A54AaABAg", "video_id": "-_0Nfgut_N0"}, {"id": "Ugy9_flrg-gyVFzPZoB4AaABAg", "text": "Really enjoying your content!!  Keep em coming!", "author": "@Grunt21Tennessee", "like_count": 1, "published_at": "2023-10-02T13:13:32Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugy9_flrg-gyVFzPZoB4AaABAg.9vMxpGfA1df9vN1RAO0dL8", "text": "Thanks!! I''ll have the back 9 up this week as well!", "author": "@golfwithjames", "like_count": 1, "published_at": "2023-10-02T13:53:48Z", "parent_id": "Ugy9_flrg-gyVFzPZoB4AaABAg", "video_id": "-_0Nfgut_N0"}, {"id": "Ugye8cE6OdxceBq8nOl4AaABAg", "text": "Dear Sir,\r\nI''m a big fan of your channel and I regularly follow your videos. I have expertise in YouTube SEO and digital marketing. After reviewing your channel, I identified 10 possible reasons why your subscriber and view count are not improving as expected.\r\nIf you''d like, I can offer you a free channel audit and even create a professional audio for your video intro. Please reply, Sir\n\n\u2014I''d love to assist you in growing your channel.", "author": "@saidulvm", "like_count": 0, "published_at": "2025-04-14T04:07:55Z", "parent_id": null, "video_id": "urwBJvYOtx0"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('airport-area', '2026-04-29 05:44:29.792235', 3400.2223362668137, NULL, NULL, NULL, 0.037, 74.0, 2.48, 96.73, 75.0, 82.0, '["u6UkKROqp4o", "C6-EaPTXS2w", "5nZ4Y0ZjUyI", "vt8EQpnBvSA", "JswV9KXrhRk", "Z12Xcb5GsrQ", "gP30unbU9pk", "srt2NuMUmpk"]', '[{"id": "UgxGA5BkjkelKWnHce14AaABAg", "text": "Can you do a pro and con discussion of Santa Ana, especially with the tram/streetcar happening and what are good areas of Santa Ana, especially as it is pretty close to Irvine but seems less expensive. Do you think Santa Ana is changing, i.e., getting better? Thank you.", "author": "@yasa7149", "like_count": 0, "published_at": "2024-01-05T08:05:57Z", "parent_id": null, "video_id": "u6UkKROqp4o"}, {"id": "Ugx2X_BtiVvjWd-c9sF4AaABAg", "text": "We rent via Airbnb an apartment at Michelson st for 1 month and an another apartment at One Uptown Newport at Jamboree st for another month and we fall in love with the area!! \nWe are thinking seriously to move out from Greece to Irvine if we manage  to get a visa in order to work there.  We love Irvine and Tustin, OC rocks!!", "author": "@michaelvassilopanagos4462", "like_count": 2, "published_at": "2023-12-31T01:32:53Z", "parent_id": null, "video_id": "u6UkKROqp4o"}, {"id": "Ugx2X_BtiVvjWd-c9sF4AaABAg.9yySBKgksz99yylv7nEkny", "text": "It''s definitely a great place!", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-12-31T04:34:02Z", "parent_id": "Ugx2X_BtiVvjWd-c9sF4AaABAg", "video_id": "u6UkKROqp4o"}, {"id": "UgzXxtWNxwdmU6hsNbF4AaABAg", "text": "Thank you so much for these videos", "author": "@pinkshoes3378", "like_count": 1, "published_at": "2023-12-30T21:20:59Z", "parent_id": null, "video_id": "u6UkKROqp4o"}, {"id": "UgzXxtWNxwdmU6hsNbF4AaABAg.9yy-MOS20029yylwWoFJ6O", "text": "Thank you for watching!", "author": "@LivinginOrangeCounty", "like_count": 0, "published_at": "2023-12-31T04:34:14Z", "parent_id": "UgzXxtWNxwdmU6hsNbF4AaABAg", "video_id": "u6UkKROqp4o"}, {"id": "UgzKmg42xcyurClDUtl4AaABAg", "text": "I know where you guys are. I visited that LA Fitness. It\u2019s also nearby my private practice.", "author": "@kaleimaile", "like_count": 1, "published_at": "2023-12-30T21:10:00Z", "parent_id": null, "video_id": "u6UkKROqp4o"}, {"id": "UgzKmg42xcyurClDUtl4AaABAg.9yxz5uZKO3w9yylyKWgdur", "text": "That''s cool!", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-12-31T04:34:29Z", "parent_id": "UgzKmg42xcyurClDUtl4AaABAg", "video_id": "u6UkKROqp4o"}, {"id": "UgzNSkLjI31gVhSJ_Px4AaABAg", "text": "Damm I\u2019m poor", "author": "@jacobrahe8726", "like_count": 1, "published_at": "2026-04-20T07:54:14Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "UgxsylO6Rx1UiT9GWYt4AaABAg", "text": "Thank so you so much for these videos. Extremely helpful especially since me and my girlfriend are in similar situations.", "author": "@dylantapang7012", "like_count": 2, "published_at": "2025-03-11T03:02:40Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "UgwJqByV_INLZJM4IOt4AaABAg", "text": "Have you guys checked the Promenade at Irvine Spectrum?", "author": "@amrit5516", "like_count": 1, "published_at": "2025-01-14T00:16:00Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "UgzMYksP8rnp7daGKq94AaABAg", "text": "If you do look into Irvine, try the enclave. It\u2019s near south coast plaza.", "author": "@evalad0", "like_count": 6, "published_at": "2024-07-28T06:32:16Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "UgyCy-35Cqnu2niL4vR4AaABAg", "text": "Very helpful video, thank you for including name of property, price, and pros + cons!! I LOVE the shower in apartment #2 as well! Btw I''ve seen very bad reviews for all the Broadstone apartments. I''m also in a similar situation and looking for a 1BR and den too so this was great!", "author": "@vanessaxlei", "like_count": 3, "published_at": "2024-06-18T20:38:20Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "Ugyqi8Ug_GDcJBRnrcJ4AaABAg", "text": "I love vlogs like these!", "author": "@marydanessa", "like_count": 1, "published_at": "2024-04-14T22:02:03Z", "parent_id": null, "video_id": "5nZ4Y0ZjUyI"}, {"id": "UgzCc79uPOBSPSyoUcZ4AaABAg", "text": "Welcome to the tour of this condo in the Watermarke community in Irvine!\nWhat do you think about this type of home \u2014 would you consider a resort-style condo like this, or do you prefer a single-family home in Irvine? I\u2019d love to hear your thoughts.\nThis property is listed by Amina Yazouri with Onyx Homes. If you are interested in the home, please contact the listing agent directly.\nIf you\u2019d like to see more home tours and learn about different communities in Irvine and Orange County, feel free to subscribe to the channel. I share walkthroughs and market insights to help buyers better understand the local real estate market.", "author": "@zengrealestate", "like_count": 0, "published_at": "2026-03-21T04:49:56Z", "parent_id": null, "video_id": "JswV9KXrhRk"}, {"id": "UgxrRvhijxyfxiQ5F2J4AaABAg", "text": "If you work from home try Thailand or Vietnam. You get a better apartment with an ocean view free daily cleaning service for $850/month", "author": "@hash_value", "like_count": 0, "published_at": "2026-04-05T13:02:57Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "text": "I hate the extraneous noises of apartment living. That''s why I bought a house.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:07:15Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg.AU9leOfMix5AUNRnLyJwxT", "text": "Good for you!!!! House privacy is the best tbh", "author": "@theamericanexplorer", "like_count": 0, "published_at": "2026-03-15T12:34:20Z", "parent_id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "Ugx_SBkM3eJCHRl0F2l4AaABAg", "text": "Don\u2019t do it find another place another state", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:17:28Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg", "text": "Welcome to California. Welcome to Orange County the Irvine development company building huge compounds to shuffling people. That is their goal. Heavy taxes have a government and you will get nothing.", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:12:24Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg.APFXOwGwUjaAU9qUUTiJCP", "text": "Lady, you don''t know what you''re talking about. \n1) Renters don''t pay property taxes on their apartment. \n2) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \n3) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \n4) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:49:27Z", "parent_id": "UgzskPqRyemqVIE5NnR4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgwBv8B2eGpjpqi2XNt4AaABAg", "text": "Just one big heaping mound of regret why would you don\u2019t do it?", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:10:58Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "text": "I hope you love taxes and heavy government. Enjoy", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:56Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg.APFWlsu6i1DAU9rD00IBtZ", "text": "Lady, you don''t know what you''re talking about. \r\n1) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \r\n2) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \r\n3) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \r\nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.\r\n\r\nThe reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:55:48Z", "parent_id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg", "text": "Why would you buy a property in California?\ud83d\ude02 What an absolute joke", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:30Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rTCJbL30", "text": "Lady, the reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:58:01Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rnxx2Wqd", "text": "rockyrodes5 She doesn''t care about facts. She''s just a Republican with a hard need to vent against California, the 4th largest economy in the world.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T06:00:59Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('northpark', '2026-04-29 05:46:12.269057', 3400.2223362668137, NULL, NULL, NULL, 0.078, 76.21, 2.48, 78.78, 75.0, 82.0, '["T6NXj9U1Hvc", "W6lpaIJwuFE", "bObfO4TBW2Y", "LLK3uETm-z4", "XOY92a8t9iM", "uRfxnNZNucc", "MdxRoOt6w8o", "kg1Vzy3KwSU", "lodJQ9yhhuI", "rQnl3wVdMtk"]', '[{"id": "Ugyo5nZxiN4BgQWaFul4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2022-08-05T01:36:14Z", "parent_id": null, "video_id": "bObfO4TBW2Y"}, {"id": "UgwUFiPTAO9pf7ieSYl4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2022-08-03T22:05:06Z", "parent_id": null, "video_id": "MdxRoOt6w8o"}, {"id": "UgzXVes_kNn2oddda3B4AaABAg", "text": "4) You don''t like to get ripped off doing errands", "author": "@hoaxnineteen", "like_count": 0, "published_at": "2026-04-24T19:27:08Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "text": "They lie about the safety in Irvine, I watched a couple flip their car and die on Alton, never made the news, kid recently died on his e-bike on keystone and regal, never makes the news or google search, no one can drive, we all know why\u2026", "author": "@SuperBaconFishing", "like_count": 3, "published_at": "2025-12-22T21:51:49Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg.AR2ibogH6dHAT-J0ogH1a-", "text": "Another reason is Chinese birth tourism, and nobody knows how to drive speak English", "author": "@IVvOOvVI", "like_count": 0, "published_at": "2026-02-09T07:04:30Z", "parent_id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "Ugyu5pjHyapyDRLQtpN4AaABAg", "text": "lol poor people reasoning... lol very simple, you can''t afford it, what a dumbass", "author": "@andrewstephen6493", "like_count": 0, "published_at": "2025-11-13T17:50:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugxu-xIJAOWTG9oOhQR4AaABAg", "text": "Buddy it\u2019s the safest country in the us", "author": "@Yoojian12", "like_count": 1, "published_at": "2025-10-06T22:46:04Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "UgwzBZLRpM9mDrGfTlJ4AaABAg", "text": "The elites need Californians to disapear or move away, thats theirs now.", "author": "@bmc9504", "like_count": 0, "published_at": "2024-05-22T20:41:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg", "text": "What''s up with the outfit, my guy \ud83d\ude02 I''m from Irvine so maybe don''t live here if ya hate it so much! \u2764", "author": "@kikilee7162", "like_count": 1, "published_at": "2024-05-22T19:36:24Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg.A3karJdRjfRA3kdlgWP805", "text": "Never said I hate it. \ud83d\ude0a", "author": "@LivingInIrvineCalif", "like_count": 0, "published_at": "2024-05-22T20:01:51Z", "parent_id": "Ugze1vj-7CZpBt9IEu94AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "UgxSQg0KVz7s-kVwDtR4AaABAg", "text": "U can keep that trash state", "author": "@pure_blood1", "like_count": 4, "published_at": "2024-05-22T15:45:33Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugzi_kMqXU1Iwoi_6754AaABAg", "text": "CA house and rental prices,gas price, grocery prices, restaurant prices,insurance costs,repair costs", "author": "@coletanner5193", "like_count": 2, "published_at": "2024-05-22T13:30:15Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('northwood-pointe', '2026-04-29 05:46:35.589198', 3400.2223362668137, NULL, NULL, NULL, 0.005, 72.27, 2.48, 72.79, 68.0, 75.0, '["dk9IVimGFTw", "btg9IR_pY2Y", "ODIcwXc02mw", "KI5UBittvXM", "boT5DROWr0Q", "1sKUs9DxK7I", "2BVDD-_gUnY", "xOpoFD6HbD0", "SV-_KOL3Vf4", "bV0lTbYmMRQ"]', '[{"id": "UgxEzJNEdnCyA4AaCMJ4AaABAg", "text": "11:14 The house where Janelle Cruz was killed by the Golden State Killer RIP", "author": "@JesusGarcia-kl3rf", "like_count": 0, "published_at": "2026-02-16T21:35:45Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx-HS5Gi1lF2f8oodB4AaABAg", "text": "Thanks for the amazing information. From UK London", "author": "@jdxaofficial", "like_count": 1, "published_at": "2025-12-03T20:12:52Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgztpdqR7Fa8IVIC-894AaABAg", "text": "Anyone looking for a new or newer built home in Irvine, especially in the newer neighborhoods, you better be prepared to pay north of $2.0MM for an average size home.  Considering you will be assessed property taxes at the market value of the home along with two HOAs, even if you have $1.0MM to put as down payment, your monthly bill for all of the above will still be a boat load ! ! !\n\nSo a professional couple pulling in $400K/yr probably can swing this neighborhood. \n\nTraffic has beome a nightmare and people are driving like there is no tomorrow. With all the foreigners coming here and not know the traffic laws, you better have eyes on the back of your head!\n\nI spoke with an officer from the Irvine PD about the traffic and he said there isn''t much they can do unless there is an incident. So until someone smashes into your vehicle, don''t look for help from the Irvine PD ! ! !\n\nLastly, this is a master planned community and Irivne being a DEI community, they have painted huge portions of the roadway for bicycles ! ! !  This encroaches on roadways for normal traffic!  I never ever see any bicycles on these marked off portion fo the roads but that''s Irvine putting taxpayers'' money to waste!", "author": "@LWRC", "like_count": 1, "published_at": "2024-08-26T23:49:04Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgxLYOC0IqIKn8mIfVx4AaABAg", "text": "Gr\u00fcne Welle (Green Wave Traffic lights) like germany", "author": "@dr.mirano", "like_count": 0, "published_at": "2023-06-08T04:29:16Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgzE9hZpLHws9Wo6U854AaABAg", "text": "Thank you for being the spokespersons for irvine", "author": "@afterburner5560", "like_count": 0, "published_at": "2023-05-28T06:44:32Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg", "text": "Nice!  When I am in the market for a condo, I will call you. Are there condo\u2019s that aren\u2019t HOA\u2019s in HB or Costa Mesa?", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:25:18Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHV-OcIY5", "text": "HI Kalei ! \nThere aren''t any condos that I''m aware of that have no HOAs.  The reason being is that condos have shared walls, fences, etc.  The HOA dues can definitely vary from one community to the next.  When you are ready to reach out, we can go over all of different aspects of the various HOAs, including their HOA dues.", "author": "@runbamrun", "like_count": 1, "published_at": "2023-05-27T21:43:59Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHye9laNE", "text": "@runbamrun , I need prices to go down before I could afford a house.", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:48:10Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}, {"id": "Ugx7J4ApIRFQ9ve10F54AaABAg", "text": "======\nFull Channel:   https://bit.ly/3NXecX3\n======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-10-17T05:42:33Z", "parent_id": null, "video_id": "1sKUs9DxK7I"}, {"id": "UgzTTJyb8aF-pcvuY4Z4AaABAg", "text": "Thank you. I really appreciate \ud83d\ude4f your video. I had looked at several Irvine Company apartments a few years ago. But I was not in a position to afford one. Center Point, after seeing your video is now my favorite. I do remember going there and how pretty the community is, resort like, greenery, stunning property. As you said, it is like it''s own City. Second choice which I saw was The Park. I had seem more, but these two are still my top two. I will go back to work this year 2024 or early 2025. Planning to go see these two apartments, probably will pick Center Point, as it has more to offer. \nBoth truly beautiful complexes.", "author": "@cm9859", "like_count": 1, "published_at": "2024-05-18T19:14:46Z", "parent_id": null, "video_id": "SV-_KOL3Vf4"}, {"id": "UgwSy_RwV7mdkh_IIMR4AaABAg", "text": "Never seen a 4 million dollar home without a pool. Yup another overpriced listing.", "author": "@delarose8769", "like_count": 0, "published_at": "2023-02-01T00:16:23Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "Ugwp_SOwskgHN4L0FS54AaABAg", "text": "\ud83d\ude0d\ud83d\ude0d\ud83d\udcaf\ud83d\ude18. Increase your stats = \"PromoSM\" .", "author": "@jirkapaidar3516", "like_count": 0, "published_at": "2023-01-17T14:22:01Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "UgwzppLny5A2IqHv9_N4AaABAg", "text": "\ud83e\udee1", "author": "@moonlightfitz", "like_count": 0, "published_at": "2023-01-14T05:05:34Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "UgznEcle2t_deBQAedF4AaABAg", "text": "This vid just has insane quality production. Keep up the great work!!", "author": "@joshuadistura7450", "like_count": 0, "published_at": "2023-01-02T07:22:04Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "UgznEcle2t_deBQAedF4AaABAg.9kNNaHDnfuq9kfLLeWv26_", "text": "Thank you Josh!", "author": "@homeswithkim", "like_count": 1, "published_at": "2023-01-09T16:08:02Z", "parent_id": "UgznEcle2t_deBQAedF4AaABAg", "video_id": "bV0lTbYmMRQ"}, {"id": "Ugz0m_gWr65u5le_c_d4AaABAg", "text": "Video quality is insane. Keep up the good work\u2764\ufe0f", "author": "@oshada9945", "like_count": 2, "published_at": "2023-01-02T04:54:20Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "Ugz0m_gWr65u5le_c_d4AaABAg.9kN6gBTr7Bc9kNAMCnNj9q", "text": "Thank you so much for your support! \u2764\ufe0f\u2764\ufe0f\u2764\ufe0f", "author": "@homeswithkim", "like_count": 0, "published_at": "2023-01-02T05:26:25Z", "parent_id": "Ugz0m_gWr65u5le_c_d4AaABAg", "video_id": "bV0lTbYmMRQ"}, {"id": "UgzN4voGOZ8SSbyaxZl4AaABAg", "text": "BEAUTIFUL HOME, however the homes in that area are *VERY CLOSE* to each other.", "author": "@tumarbongrox6074", "like_count": 0, "published_at": "2023-01-01T23:33:32Z", "parent_id": null, "video_id": "bV0lTbYmMRQ"}, {"id": "UgzN4voGOZ8SSbyaxZl4AaABAg.9kMXy_dL_dW9kM_jwYptpN", "text": "They''re a bit close but as a result you''re able to get the panoramic moutain view. It''s an area next to many great schools, shops, and dining as well. What area do you think we should look at next? :)", "author": "@homeswithkim", "like_count": 1, "published_at": "2023-01-01T23:57:45Z", "parent_id": "UgzN4voGOZ8SSbyaxZl4AaABAg", "video_id": "bV0lTbYmMRQ"}, {"id": "UgzN4voGOZ8SSbyaxZl4AaABAg.9kMXy_dL_dW9kMdfN4nsux", "text": "@homeswithkim Irvine is a great area!  You are right a potential home buyer for that home must compromise the closeness of the homes for a great mountain view.  Your presentation of the home was detailed and informative.  I''m a new sub.  I''m helping my sister look for homes in the southern California area.  She likes the San Diego area.  Keep the great videos coming \ud83d\udc4d", "author": "@tumarbongrox6074", "like_count": 0, "published_at": "2023-01-02T00:32:05Z", "parent_id": "UgzN4voGOZ8SSbyaxZl4AaABAg", "video_id": "bV0lTbYmMRQ"}, {"id": "UgzN4voGOZ8SSbyaxZl4AaABAg.9kMXy_dL_dW9kMf47S-2ox", "text": "@tumarbongrox6074 Thank you very much for your support! If you need any help searching for homes in San Diego for your sister, please feel free to reach out \ud83d\ude0a", "author": "@homeswithkim", "like_count": 1, "published_at": "2023-01-02T00:44:20Z", "parent_id": "UgzN4voGOZ8SSbyaxZl4AaABAg", "video_id": "bV0lTbYmMRQ"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('orangetree', '2026-04-29 05:47:09.584933', 3400.2223362668137, NULL, NULL, NULL, 0.015, 72.81, 2.48, 79.92, 68.0, 75.0, '["5tu2lcRB-RU", "LES1YP1bTsk", "97VPkxTfAQ4", "dDJ62hXVKms", "bbesnMizEAU", "SwY_pGHWoTM", "zPys4MnjLQo", "k3T6DzCCzL4", "jb2-VPl-rao", "Mc0UKXESUgk", "-8PTPy8HsmU"]', '[{"id": "Ugw5yvRi_OrENE6568J4AaABAg", "text": "Irvine is definitely not for everyone. Most people are not millionaires.", "author": "@Domane-mh8wg", "like_count": 1, "published_at": "2026-02-26T04:25:40Z", "parent_id": null, "video_id": "97VPkxTfAQ4"}, {"id": "UgyAdunzO7lOrAbuKUh4AaABAg", "text": "Irvine\u2019s definitely great! \ud83d\udc4d\ud83c\udffc", "author": "@TexasExotic", "like_count": 1, "published_at": "2025-11-15T03:04:18Z", "parent_id": null, "video_id": "97VPkxTfAQ4"}, {"id": "UgyAdunzO7lOrAbuKUh4AaABAg.APXRAHKmCtAAPYuNLcJVSb", "text": "It sure is! What\u2019s your favorite place in Irvine to go to?", "author": "@LivinginOrangeCountyExperts", "like_count": 0, "published_at": "2025-11-15T16:47:28Z", "parent_id": "UgyAdunzO7lOrAbuKUh4AaABAg", "video_id": "97VPkxTfAQ4"}, {"id": "UgyBO-IUbpvFJ64IsDd4AaABAg", "text": "Cool", "author": "@NikoBedi", "like_count": 0, "published_at": "2025-07-21T14:40:14Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "Ugwdq9REbfZ9Asyuvnl4AaABAg", "text": "Great Job Doug and Rachel!!  Wonderful tour \ud83c\udf89\ud83c\udf89", "author": "@TheNewportBeachLife", "like_count": 0, "published_at": "2025-02-15T22:35:19Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgxAhNYV25Tu-W-oW7J4AaABAg", "text": "Nice video.  Could you do a similar video on Orchard Hills?", "author": "@bladerunnin67", "like_count": 1, "published_at": "2024-04-25T20:17:46Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgxAhNYV25Tu-W-oW7J4AaABAg.A2f97hyH03oA2fDkDXRq17", "text": "Thank you! Yes, we sell homes in beautiful Orchard Hills, and we are working on a video to highlight this wonderful community. Thanks again!", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-25T20:58:07Z", "parent_id": "UgxAhNYV25Tu-W-oW7J4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgwUKjybrOqjj2uOCUl4AaABAg", "text": "I''ve lived in Irvine since 1968, when I hit a lottery I''ll be talking to you\ud83d\ude05 Great video!!!", "author": "@lionheartmerrill1069", "like_count": 2, "published_at": "2024-04-15T01:59:46Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgwUKjybrOqjj2uOCUl4AaABAg.A2ERWxyCz8oA2Gpipzzd6G", "text": "Thank you! \ud83d\ude0a", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-16T00:18:28Z", "parent_id": "UgwUKjybrOqjj2uOCUl4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgyQR1RFfq-zZfEM6DN4AaABAg", "text": "I can wait to live here thank you for the video and God bless you both \ud83d\ude4f\ud83c\udffe", "author": "@LamontEverage", "like_count": 2, "published_at": "2024-04-12T14:31:13Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgyQR1RFfq-zZfEM6DN4AaABAg.A28386gQrVfA2Gpl1SFQ9V", "text": "Thank you! \ud83d\ude0a \ud83d\ude4f", "author": "@swardstromgroup", "like_count": 0, "published_at": "2024-04-16T00:18:46Z", "parent_id": "UgyQR1RFfq-zZfEM6DN4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgwslS6Z_4fE6RqECYh4AaABAg", "text": "If you have visited Hidden Canyon, let us know your favorite aspect of this community in the COMMENTS below! \n\nFor Floor Plans of homes, or more information about Hidden Canyon, visit our community website - click here: https://LivingHiddenCanyon.com\nor email, call or text :\nEMAIL: Doug@SwardstromGroup.com or Rachel@SwardstromGroup.com\nPHONE: (949) 302-4883", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-12T01:14:45Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "Ugya89fVSXDbIx7OUQx4AaABAg", "text": "A lot of the Asian families live here and we can call the city of Irvine, The Asian beverlyhills.", "author": "@RickAutor-i5c", "like_count": 0, "published_at": "2025-11-23T07:00:36Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgxOYjvECfzwAaHTlRl4AaABAg", "text": "I have a question. I consider moving to Irvine from T\u00fcrkiye, but my husband is a sergeant so techically he can''t work for his own job anymore, he has to do idk detailing, storage doordash idk something will work for him in the end, but for me I am anEnglish teacher in a government school for almost 10 years here, I''ve got my TESOL, sertificates etc. Is it a smart move for us to live in Irvine because actually I want to be in somewhere safe and with good schools also a good weather. Please, inform me sincerely. Thank you all <3", "author": "@hellobuss", "like_count": 0, "published_at": "2025-09-20T20:52:54Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgxOYjvECfzwAaHTlRl4AaABAg.ANJ8wu5SExvANaUaQwgk3N", "text": "Irvine is an amazing place to live! There are pros and cons to every city, but we love it here. \u2764", "author": "@LivinginOrangeCountyExperts", "like_count": 1, "published_at": "2025-09-27T23:48:24Z", "parent_id": "UgxOYjvECfzwAaHTlRl4AaABAg", "video_id": "zPys4MnjLQo"}, {"id": "UgzH74Wiz2kOe5ugAkB4AaABAg", "text": "Huge population of Chinese expats, alot of police patrols (theyre police everywhere, hence the reason why the city was voted one of safest cities in US)  high cost of living ( rent is really high) , etc. These are some common aspects of Irvine. Its a nice town and I work there but would never considered living there, people in Irvine just arent friendly and also Ive gotten pulled over by IPD multiple times for no legitimate reason just car checks ( hence the city safety mentioned above)", "author": "@followme82365", "like_count": 0, "published_at": "2025-08-10T21:32:29Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgwykqtIts2FdvoHzQV4AaABAg", "text": "Hoping to move my family here on an EB 5 visa.", "author": "@angelo-xr8on", "like_count": 0, "published_at": "2025-04-14T14:08:52Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgwykqtIts2FdvoHzQV4AaABAg.AGu0J_PDmCkAGuHrVWjNbY", "text": "We would love to assist once you''re ready to make the move!", "author": "@LivinginOrangeCountyExperts", "like_count": 0, "published_at": "2025-04-14T16:42:11Z", "parent_id": "UgwykqtIts2FdvoHzQV4AaABAg", "video_id": "zPys4MnjLQo"}, {"id": "UgyoBY08d1zaGsDhspR4AaABAg", "text": "I need to show this to my husband to convince him to move us there!!", "author": "@lejohvu", "like_count": 2, "published_at": "2025-01-07T03:43:05Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgyoBY08d1zaGsDhspR4AaABAg.ACz7aGkGUA8AD-_LqFJiwM", "text": "Irvine is awesome! Thanks for watching!!", "author": "@LivinginOrangeCountyExperts", "like_count": 1, "published_at": "2025-01-07T17:13:37Z", "parent_id": "UgyoBY08d1zaGsDhspR4AaABAg", "video_id": "zPys4MnjLQo"}, {"id": "UgwwLr_ChXh0wGog5M54AaABAg", "text": "300k Residents yea and 299k are Asian lol,,", "author": "@bigmazem3", "like_count": 0, "published_at": "2025-01-02T22:03:19Z", "parent_id": null, "video_id": "zPys4MnjLQo"}, {"id": "UgwwLr_ChXh0wGog5M54AaABAg.ACoDXJhkk4NACvouAveViz", "text": "Thanks for watching!!", "author": "@LivinginOrangeCountyExperts", "like_count": 0, "published_at": "2025-01-05T20:53:19Z", "parent_id": "UgwwLr_ChXh0wGog5M54AaABAg", "video_id": "zPys4MnjLQo"}, {"id": "UgwvipAeSwYBlY_x5lV4AaABAg", "text": "\ud83e\udd14Thinking of Moving to Orange County California?\n\ud83d\udcdd Let me Help! \n\ud83d\udcf2 Call or Text : 949-636-0800\n\ud83d\udce9 Email: CGoodwinRealEstate@gmail.com", "author": "@LoveLivinginOrangeCountyCA", "like_count": 1, "published_at": "2025-01-29T04:46:32Z", "parent_id": null, "video_id": "Mc0UKXESUgk"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('orchard-hills', '2026-04-29 05:47:43.368287', 3400.2223362668137, NULL, NULL, NULL, 0.0, 72.0, 2.48, 68.96, 68.0, 75.0, '["4ONORtCZ3_A", "GI793RWZyE8", "kcjOxy59MqI", "ZC9Q-8RvNGw", "ux41cdNrc7w", "31duecIWz9Y", "eD92edfFJOw", "q31gVs3130U"]', '[{"id": "UgzgFqTzSiDvldBY5p54AaABAg", "text": "Summit is a \ud83c\udf6f filled mouse trap. Peak housing bubble mania. Over priced, high risk, next to a smelly dump and road noise will be a huge problem in the future.", "author": "@streetmoney21", "like_count": 0, "published_at": "2025-08-19T01:58:14Z", "parent_id": null, "video_id": "4ONORtCZ3_A"}, {"id": "UgzgFqTzSiDvldBY5p54AaABAg.ALzieKzSvluANK0h1lt_XF", "text": "Many people share your concerns!", "author": "@swardstromgroup", "like_count": 0, "published_at": "2025-09-21T05:00:04Z", "parent_id": "UgzgFqTzSiDvldBY5p54AaABAg", "video_id": "4ONORtCZ3_A"}, {"id": "Ugz4pNNcoXIEpz1ZmLV4AaABAg", "text": "nice area unfortunately it''s in a major fire factor zone 6 out of 10", "author": "@drtrt7", "like_count": 1, "published_at": "2024-10-25T22:26:03Z", "parent_id": null, "video_id": "GI793RWZyE8"}, {"id": "Ugz4pNNcoXIEpz1ZmLV4AaABAg.AA1aHMxSywVAAcYFGk0Qav", "text": "Thanks for watching! We find many areas in Orange County are now in a fire zone...High insurance costs is one of the reasons some don''t fulfill their purchase, but most homes still sell. But coupled with HOA and Mello-Roos, the sunk costs can be substantial.", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2024-11-09T16:10:41Z", "parent_id": "Ugz4pNNcoXIEpz1ZmLV4AaABAg", "video_id": "GI793RWZyE8"}, {"id": "UgzY8_jEthGhCqsVnk54AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-07-11T19:15:50Z", "parent_id": null, "video_id": "GI793RWZyE8"}, {"id": "UgxFzczC88GQ4VU4wBl4AaABAg", "text": "\ud83d\udcccHey everyone, it\u2019s Ra Theus! If you want my FREE RELOCATION GUIDE with information on all things about LOS ANGELES COUNTY, you can download it here: https://interlink.buyorsellrealestatenow.com/losangelescaliforniarelocationguide\r\n\r\nThinking of moving to or buying a property in Los Angeles, California? Let me help!\r\n\ud83d\udcf1 Call or Text: (310) 905-5037\r\n\u2709 Email: rason@rasontheus.com\r\n\ud83c\udf10 Learn more: www.rasontheus.com", "author": "@Living_in_LosAngeles", "like_count": 2, "published_at": "2025-11-08T12:25:56Z", "parent_id": null, "video_id": "kcjOxy59MqI"}, {"id": "UgzWu3swLxM4TM_fpE14AaABAg", "text": "Good elevation and grating.  Good drainage", "author": "@jaypark7207", "like_count": 1, "published_at": "2025-11-20T19:40:26Z", "parent_id": null, "video_id": "kcjOxy59MqI"}, {"id": "UgzWu3swLxM4TM_fpE14AaABAg.APl58TmnY5hAQ0K241yGOE", "text": "I totally agree!!\n\nIf you ever have questions or want help with anything real estate in LA, feel free to reach out directly \ud83d\udcf2\nRA Theus | Hoffman Theus Real Estate\n\ud83d\udce7 Rason@HoffmanTheus.com\n\ud83d\udcde (310) 950-0537", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2025-11-27T02:58:28Z", "parent_id": "UgzWu3swLxM4TM_fpE14AaABAg", "video_id": "kcjOxy59MqI"}, {"id": "UgwNJg3JQG3zVoQcUvR4AaABAg", "text": "Is this house for sale?", "author": "@stayofftheweed69420", "like_count": 0, "published_at": "2025-11-15T20:51:02Z", "parent_id": null, "video_id": "kcjOxy59MqI"}, {"id": "Ugw_b9v5HtY7f-LGhKF4AaABAg", "text": "$6 million and no his/hers primary closets. Toll does flashy houses but they always short the primary closets.", "author": "@texastriguy", "like_count": 0, "published_at": "2025-11-09T02:55:10Z", "parent_id": null, "video_id": "kcjOxy59MqI"}, {"id": "Ugw_b9v5HtY7f-LGhKF4AaABAg.APHyMA0R8KFAPSp9N1O0_j", "text": "HI @texastriguy Haha, right? Closet space can make or break a primary suite, I\u2019ve had clients say the same thing!", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2025-11-13T08:06:26Z", "parent_id": "Ugw_b9v5HtY7f-LGhKF4AaABAg", "video_id": "kcjOxy59MqI"}, {"id": "Ugy8VsJ8JnoM-wyCAnZ4AaABAg", "text": "Wow\u2764\u2764\u2764", "author": "@JhonatanJhonatanwiliam", "like_count": 0, "published_at": "2026-02-12T13:27:50Z", "parent_id": null, "video_id": "ZC9Q-8RvNGw"}, {"id": "UgwZ1tvgQaqssP1LAyF4AaABAg", "text": "\ud83d\udcccHey everyone, it\u2019s Ra Theus! If you want my FREE RELOCATION GUIDE with information on all things about LOS ANGELES COUNTY, you can download it here: https://interlink.buyorsellrealestatenow.com/losangelescaliforniarelocationguide\r\n\r\nThinking of moving to or buying a property in Los Angeles, California? Let me help!\r\n\ud83d\udcf1 Call or Text: (310) 905-5037\r\n\u2709 Email: rason@rasontheus.com\r\n\ud83c\udf10 Learn more: www.rasontheus.com", "author": "@Living_in_LosAngeles", "like_count": 1, "published_at": "2025-10-19T04:35:50Z", "parent_id": null, "video_id": "31duecIWz9Y"}, {"id": "UgxkscJaVeqVW7ia_BZ4AaABAg", "text": "\ud83d\ude4f\ud83c\udffb\ud83d\udc90\ud83d\udc90\ud83d\udc90\ud83d\udc90\ud83d\udc90\ud83d\udc90\ud83d\udc90\ud83d\ude4f\ud83c\udffb\ud83e\udd70\ud83e\udd17", "author": "@PrinceKumar-cf7ek", "like_count": 1, "published_at": "2026-01-22T16:31:43Z", "parent_id": null, "video_id": "31duecIWz9Y"}, {"id": "UgxkscJaVeqVW7ia_BZ4AaABAg.ASHycRmz6gwASX7PeScfZk", "text": "Thank you for watching \ud83d\udc4d", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2026-01-28T13:45:49Z", "parent_id": "UgxkscJaVeqVW7ia_BZ4AaABAg", "video_id": "31duecIWz9Y"}, {"id": "UgxwtWKqTKwlROBCfZ14AaABAg", "text": "The long catwalk suspended in the air makes me very nervous, especially with little kids and elderly, regardless of the glass banister. The primary bathroom is beautiful, but I''m disappointed in the layout. The primary bedroom should come first after the entrance, the bathroom and closet after. Also, I feel the master closet should be bigger for the price of the house. The size of the primary bedroom, bathroom, and closet matters for a couple. Just my honest thoughts.", "author": "@timothykassisieh9701", "like_count": 0, "published_at": "2026-01-06T04:15:03Z", "parent_id": null, "video_id": "31duecIWz9Y"}, {"id": "UgxwtWKqTKwlROBCfZ14AaABAg.ARcSatgCiVwARfcwo7jc80", "text": "It''s interesting how different features like the catwalk and room layouts resonate with people, and it''s totally understandable to prioritize safety and practical space like closet size in a luxury home.", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2026-01-07T09:51:53Z", "parent_id": "UgxwtWKqTKwlROBCfZ14AaABAg", "video_id": "31duecIWz9Y"}, {"id": "UgzGLZUqEdOfH5xcBwF4AaABAg", "text": "bro''s looking like a clown.... get shoes that fit right....", "author": "@ktranization", "like_count": 0, "published_at": "2026-01-05T23:03:27Z", "parent_id": null, "video_id": "31duecIWz9Y"}, {"id": "UgzGLZUqEdOfH5xcBwF4AaABAg.ARbtwkF98_kARfd4Ol49MR", "text": "Thank you for watching \ud83d\udc4d", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2026-01-07T09:53:03Z", "parent_id": "UgzGLZUqEdOfH5xcBwF4AaABAg", "video_id": "31duecIWz9Y"}, {"id": "UgyFtBgiqJvIi3eZvTt4AaABAg", "text": "Nearky $8 million gets you a fully custom new construction home in a killer Newport hood. Irvine? Tract home? Get real. People in Irvine have no taste.", "author": "@OwlFriendsDM", "like_count": 0, "published_at": "2025-12-11T05:12:45Z", "parent_id": null, "video_id": "31duecIWz9Y"}, {"id": "UgyFtBgiqJvIi3eZvTt4AaABAg.AQ_bXlnj-trAQjOz1HYXbf", "text": "Where do you live?", "author": "@dst6517", "like_count": 0, "published_at": "2025-12-15T00:26:41Z", "parent_id": "UgyFtBgiqJvIi3eZvTt4AaABAg", "video_id": "31duecIWz9Y"}, {"id": "UgyFtBgiqJvIi3eZvTt4AaABAg.AQ_bXlnj-trAQpTZu1DL7s", "text": "Thanks for your comment! The real estate market has something for everyone.", "author": "@Living_in_LosAngeles", "like_count": 0, "published_at": "2025-12-17T09:02:15Z", "parent_id": "UgyFtBgiqJvIi3eZvTt4AaABAg", "video_id": "31duecIWz9Y"}, {"id": "UgwlUigKg8VvQ0UBTCZ4AaABAg", "text": "I have a 10,000 sq ft house with better views in North Tustin for less $$$", "author": "@domingoferrari5889", "like_count": 0, "published_at": "2025-11-24T01:27:59Z", "parent_id": null, "video_id": "eD92edfFJOw"}, {"id": "UgwUgQer9mueX0SS5vd4AaABAg", "text": "WHY.....?", "author": "@johnnguyen699", "like_count": 0, "published_at": "2025-11-19T07:01:06Z", "parent_id": null, "video_id": "eD92edfFJOw"}, {"id": "UgxxkwzRCX-KSGovCAN4AaABAg", "text": "House is wow", "author": "@joeydeleon750", "like_count": 1, "published_at": "2025-11-18T02:10:06Z", "parent_id": null, "video_id": "eD92edfFJOw"}, {"id": "UgzJ6vBZtwnlqC4RNgZ4AaABAg", "text": "\ud83d\udcccHey everyone, it\u2019s Ra Theus! If you want my FREE RELOCATION GUIDE with information on all things about LOS ANGELES COUNTY, you can download it here: https://interlink.buyorsellrealestatenow.com/losangelescaliforniarelocationguide\r\n\r\nThinking of moving to or buying a property in Los Angeles, California? Let me help!\r\n\ud83d\udcf1 Call or Text: (310) 905-5037\r\n\u2709 Email: rason@rasontheus.com\r\n\ud83c\udf10 Learn more: www.rasontheus.com", "author": "@Living_in_LosAngeles", "like_count": 1, "published_at": "2025-11-01T12:22:46Z", "parent_id": null, "video_id": "q31gVs3130U"}, {"id": "Ugz8RowMGPajvyrV4WJ4AaABAg", "text": "For a little over $4 million, the Saddle Crest community offers larger, better appointed homes on larger lots and not too far from the Orchard Hills area, but without the exorbitant price premium. Ra - you should check them out and do a video on those homes. The \"Sage\" residence offers 5700 sq ft, a 4 car garage space, 2 powder rooms, primary bath with dual water closets and two closets, and even an elevator (which is great for getting heavy stuff to the 2nd floor even for us younger peeps!). And the lots are larger, too.  Worth a look for sure.", "author": "@texastriguy", "like_count": 2, "published_at": "2025-11-02T05:51:46Z", "parent_id": null, "video_id": "q31gVs3130U"}, {"id": "Ugz8RowMGPajvyrV4WJ4AaABAg.AP0G-OCeQFPAP4I8o40iiO", "text": "Thank you so much for this feedback. I will go and check out those homes and make some videos.", "author": "@Living_in_LosAngeles", "like_count": 1, "published_at": "2025-11-03T19:27:29Z", "parent_id": "Ugz8RowMGPajvyrV4WJ4AaABAg", "video_id": "q31gVs3130U"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('shady-canyon', '2026-04-29 05:48:06.127739', 3400.2223362668137, NULL, NULL, NULL, 0.0, 72.0, 2.48, 60.03, 62.0, 69.0, '["IFri3Ejn7AM", "XGAII7QXehE", "4J-LXk47vFA", "mXHfFK0YxTQ", "0_YJmOxW2lk", "jvyCLWHR_WY", "KxIEwtKKUJQ", "8YNf4EJggvg"]', '[{"id": "UgwSfSEZnajI2bHRjLF4AaABAg", "text": "She is of course misrepresenting reality to move her imaginary goal post. Look up the stats yourself. At least be specific if you are going to make a statement like this because the average person in Irvine makes way less than that. She is conflating individual with household income. Even the average household income in Irvine is less than her arbitrary figure.", "author": "@kevinb4865", "like_count": 1, "published_at": "2026-04-27T21:42:09Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgwW5OF380uo3zMl3Ex4AaABAg", "text": "Is it worth it?", "author": "@usairmx", "like_count": 0, "published_at": "2026-04-06T11:30:06Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzZW-eWn69kLxK4I4Z4AaABAg", "text": "Irvine...sleepy place...with the roar of freeways at a number of neighborhoods.", "author": "@marcmorin2129", "like_count": 0, "published_at": "2026-03-20T03:56:59Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwlr4My4cvpfEYcyyF4AaABAg", "text": "That sounds about right or a little less...you can afford a 1 bed room high rise. Older 2 bd condos 900k to start. Great Park just Mello and HOA set you back 1400 to -1600 per month ...Any house in OC decent safe starts at 1.1mm", "author": "@sallycoo5527", "like_count": 0, "published_at": "2026-02-09T04:08:50Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugzyc_zneQ_H7l8GZsd4AaABAg", "text": "I live down the street and yes most apartment homes are over a million", "author": "@dg8676", "like_count": 1, "published_at": "2026-01-02T15:30:23Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgyXzoaz9Ie2z9d7WVd4AaABAg", "text": "I grew up in Irvine and still live here. With that statistic you just said I would say the majority of people that live here now are considered low income. They have built so many more apartments here now.", "author": "@wali82", "like_count": 0, "published_at": "2025-12-24T16:09:09Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzXttZ4Tz_S4mML3-N4AaABAg", "text": "That\u2019s fair, suspicious and interesting at the same time.", "author": "@ashleymoore_12_99", "like_count": 0, "published_at": "2025-11-10T22:49:38Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgwHUXQjrjb23ztHH2R4AaABAg", "text": "And also extremely boring and cookie cutter homes.", "author": "@alfonsonuno", "like_count": 0, "published_at": "2025-09-15T00:23:49Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwcqo5nsoQK9kXD06h4AaABAg", "text": "Quote the source ?", "author": "@Gary-v7j", "like_count": 0, "published_at": "2025-09-07T18:48:26Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg", "text": "I\u2019m a cyber hacker and stole 1.7 million in 2022 and have made money along the way Irvine is rich and very nice to live if you got money", "author": "@booogiee1258", "like_count": 1, "published_at": "2025-06-22T20:36:29Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg.AJgNWuK3SaYAOBpC42KwgU", "text": "Right\u2026.", "author": "@alexc08", "like_count": 0, "published_at": "2025-10-12T21:08:19Z", "parent_id": "UgzY-nqUFf_L5mV9LX54AaABAg", "video_id": "IFri3Ejn7AM"}, {"id": "UgxUDN-kHLwxt8-L5rp4AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\n\ud83d\udcf1Call or text:  949-285-1207\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-07-20T01:01:27Z", "parent_id": null, "video_id": "jvyCLWHR_WY"}, {"id": "Ugy_IBOv4k_daw1DR0d4AaABAg", "text": "a lot of shady people live in that canyon?", "author": "@seinundzeiten", "like_count": 1, "published_at": "2023-12-18T04:39:33Z", "parent_id": null, "video_id": "jvyCLWHR_WY"}, {"id": "Ugy_IBOv4k_daw1DR0d4AaABAg.9ySJD2aBR3C9yZrVDl3I_i", "text": "LOL - haven''t ran into any! Great community \ud83d\udc4d", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-12-21T03:02:33Z", "parent_id": "Ugy_IBOv4k_daw1DR0d4AaABAg", "video_id": "jvyCLWHR_WY"}, {"id": "UgwMUWY_O9CyCnM72nh4AaABAg", "text": "HOA here are bunch of lying gaslighters.", "author": "@kwangkim4917", "like_count": 0, "published_at": "2023-04-25T00:38:38Z", "parent_id": null, "video_id": "jvyCLWHR_WY"}, {"id": "UgwMUWY_O9CyCnM72nh4AaABAg.9oucF8tifa39oxBlwmVJ-Y", "text": "Hi Kwang,\nThanks for watching our videos! HOA''s are certainly not everyones ''favorite.'' What do you find you don''t like about the one in Shady Canyon?", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-04-26T00:36:17Z", "parent_id": "UgwMUWY_O9CyCnM72nh4AaABAg", "video_id": "jvyCLWHR_WY"}, {"id": "UgyKIvIoAo6kJqHvGct4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-07-23T22:59:45Z", "parent_id": null, "video_id": "KxIEwtKKUJQ"}, {"id": "Ugxsz9Lq5VQ5aGd5FxZ4AaABAg", "text": "\u5149\u7a81\u7a81\u7684\u540e\u9662\uff0c\u5f88\u96be\u770b", "author": "@andrewxu4165", "like_count": 0, "published_at": "2023-08-12T23:48:41Z", "parent_id": null, "video_id": "8YNf4EJggvg"}, {"id": "UgwfBCrSZAO8o_ELReh4AaABAg", "text": "Where is this located? What\u2019s the asking price?", "author": "@paris1934", "like_count": 0, "published_at": "2023-08-12T19:35:02Z", "parent_id": null, "video_id": "8YNf4EJggvg"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('irvine-spectrum', '2026-04-29 05:40:59.715737', 3400.2223362668137, NULL, NULL, NULL, 0.137, 79.4, 2.48, 88.9, 75.0, 82.0, '["IFri3Ejn7AM", "LjRl4aEWnSo", "VlihgtoWi8E", "iyp1Pk4k6is", "7dKmgDgUuhU", "PE429i3aCdY", "vtkr-PT4Bcs", "srt2NuMUmpk", "npR2EkyPXbo", "tNQt4HTwLbo"]', '[{"id": "UgwSfSEZnajI2bHRjLF4AaABAg", "text": "She is of course misrepresenting reality to move her imaginary goal post. Look up the stats yourself. At least be specific if you are going to make a statement like this because the average person in Irvine makes way less than that. She is conflating individual with household income. Even the average household income in Irvine is less than her arbitrary figure.", "author": "@kevinb4865", "like_count": 1, "published_at": "2026-04-27T21:42:09Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgwW5OF380uo3zMl3Ex4AaABAg", "text": "Is it worth it?", "author": "@usairmx", "like_count": 0, "published_at": "2026-04-06T11:30:06Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzZW-eWn69kLxK4I4Z4AaABAg", "text": "Irvine...sleepy place...with the roar of freeways at a number of neighborhoods.", "author": "@marcmorin2129", "like_count": 0, "published_at": "2026-03-20T03:56:59Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwlr4My4cvpfEYcyyF4AaABAg", "text": "That sounds about right or a little less...you can afford a 1 bed room high rise. Older 2 bd condos 900k to start. Great Park just Mello and HOA set you back 1400 to -1600 per month ...Any house in OC decent safe starts at 1.1mm", "author": "@sallycoo5527", "like_count": 0, "published_at": "2026-02-09T04:08:50Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugzyc_zneQ_H7l8GZsd4AaABAg", "text": "I live down the street and yes most apartment homes are over a million", "author": "@dg8676", "like_count": 1, "published_at": "2026-01-02T15:30:23Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgyXzoaz9Ie2z9d7WVd4AaABAg", "text": "I grew up in Irvine and still live here. With that statistic you just said I would say the majority of people that live here now are considered low income. They have built so many more apartments here now.", "author": "@wali82", "like_count": 0, "published_at": "2025-12-24T16:09:09Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzXttZ4Tz_S4mML3-N4AaABAg", "text": "That\u2019s fair, suspicious and interesting at the same time.", "author": "@ashleymoore_12_99", "like_count": 0, "published_at": "2025-11-10T22:49:38Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgwHUXQjrjb23ztHH2R4AaABAg", "text": "And also extremely boring and cookie cutter homes.", "author": "@alfonsonuno", "like_count": 0, "published_at": "2025-09-15T00:23:49Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwcqo5nsoQK9kXD06h4AaABAg", "text": "Quote the source ?", "author": "@Gary-v7j", "like_count": 0, "published_at": "2025-09-07T18:48:26Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg", "text": "I\u2019m a cyber hacker and stole 1.7 million in 2022 and have made money along the way Irvine is rich and very nice to live if you got money", "author": "@booogiee1258", "like_count": 1, "published_at": "2025-06-22T20:36:29Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg.AJgNWuK3SaYAOBpC42KwgU", "text": "Right\u2026.", "author": "@alexc08", "like_count": 0, "published_at": "2025-10-12T21:08:19Z", "parent_id": "UgzY-nqUFf_L5mV9LX54AaABAg", "video_id": "IFri3Ejn7AM"}, {"id": "Ugy7vKlUbD5N3D59Wch4AaABAg", "text": "Thank you Lord! You have no idea how much these videos help", "author": "@vanessanoheart", "like_count": 1, "published_at": "2026-03-03T17:16:21Z", "parent_id": null, "video_id": "LjRl4aEWnSo"}, {"id": "Ugy7vKlUbD5N3D59Wch4AaABAg.ATu2XHyfE4yATwf3CCoZ3c", "text": "Glad I could help, thank you for watching! \ud83d\ude4f", "author": "@PacificMotionVideo", "like_count": 1, "published_at": "2026-03-04T17:40:14Z", "parent_id": "Ugy7vKlUbD5N3D59Wch4AaABAg", "video_id": "LjRl4aEWnSo"}, {"id": "UgzjZKy3nd3vSRBz8HV4AaABAg", "text": "*\ua9c1  Buen \ud83d\udc4c\ud83d\udc4c v\u00eddeo \ud83d\ude09 \ud83d\udc4d  \ua9c2*", "author": "@DUHOVED_FOR_RELAX", "like_count": 2, "published_at": "2023-01-30T06:02:36Z", "parent_id": null, "video_id": "iyp1Pk4k6is"}, {"id": "UgzjZKy3nd3vSRBz8HV4AaABAg.9lVKkf9EP4u9lVsnIy4Fdd", "text": "Thanks for watching", "author": "@slowsteadywalk", "like_count": 1, "published_at": "2023-01-30T11:08:47Z", "parent_id": "UgzjZKy3nd3vSRBz8HV4AaABAg", "video_id": "iyp1Pk4k6is"}, {"id": "Ugxr6fxWr8DfOXTYmQ54AaABAg", "text": "Beautiful place to walk around at night enjoy and thanks for sharing", "author": "@JefPersonalVideos", "like_count": 2, "published_at": "2023-01-27T14:54:11Z", "parent_id": null, "video_id": "iyp1Pk4k6is"}, {"id": "Ugxr6fxWr8DfOXTYmQ54AaABAg.9lOZCSncKpF9lVsmCRBEUN", "text": "Thanks for watching", "author": "@slowsteadywalk", "like_count": 1, "published_at": "2023-01-30T11:08:38Z", "parent_id": "Ugxr6fxWr8DfOXTYmQ54AaABAg", "video_id": "iyp1Pk4k6is"}, {"id": "Ugz7l40YP-WOxEVmDqF4AaABAg", "text": "My son is 17, Northwood high school. GPA over 3.5. He''s had a good high school experience. He''s not taking all AP classes and not getting tudors. Yes, if you want over a 4.0 there''s more work involved. But going to school in Irvine doesn''t require crazy amounts of work and tudors if you don''t want to go to an Ivy league school. You can still get into fine schools, haha.", "author": "@ChrisRivera-lz3lo", "like_count": 0, "published_at": "2026-04-16T21:06:47Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgyRk3mrSkDvvRbOrW94AaABAg", "text": "I raised all 3 of my kids in Woodbridge, spent half of my 72 years there. No complaints", "author": "@robertkendall1037", "like_count": 0, "published_at": "2026-03-20T16:57:45Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugwep9dq5yI_FgL7TkV4AaABAg", "text": "A family I am close to with two young children moved from Pasadena to Irvine for work. They liked Pasadena, but they have grown to like Irvine. Their rent is higher in Irvine, but they are in a nice place that is not 100 years old.", "author": "@prrosenkrantz", "like_count": 0, "published_at": "2026-02-15T07:36:33Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgyYa8UWhXGsOUlkMpx4AaABAg", "text": "\ud83e\udd14....mmm Irvine way hotter??? Somebody wants to sell more houses closer to the beach...", "author": "@Franciscodelporto", "like_count": 0, "published_at": "2026-01-12T03:22:49Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugwre5ef-NVNhqbLa1N4AaABAg", "text": "It takes time to understand Irvine.  But once you live there after a year you realize why it was built the way it is with shopping centers facing inward to prevent crime, pedestrians, and homeless.  And how it was built with 3 to 4 lane throughways to improve traffic and minimize slowing by moving entrances to shopping centers to inner streets.  And of course the master planned communities designed to mix apartments, condos and SFHs to provide diversity within each village.  Then there\u2019s the massive amount of land dedicated to parks and biking.  Irvine is intentionally the anti-city designed to improve the quality of family life.", "author": "@ap774", "like_count": 0, "published_at": "2025-11-19T15:58:27Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgybuXEX8V9EEdCu6IV4AaABAg", "text": "Irvine is so over built and the traffic is horrible. Most of the shopping centers are so crowded it can be hard to find a parking spot. It was a great place 45 years ago but no more!", "author": "@MikeB-in1nd", "like_count": 2, "published_at": "2025-08-25T23:26:09Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgybuXEX8V9EEdCu6IV4AaABAg.AMGToWgnO7lAVaacHdhsbx", "text": "they didnt have internet 45 years ago so it cant have been that good, may as well say 500 years ago for all it relates to anyone today", "author": "@drinkwater9891", "like_count": 0, "published_at": "2026-04-14T21:00:58Z", "parent_id": "UgybuXEX8V9EEdCu6IV4AaABAg", "video_id": "PE429i3aCdY"}, {"id": "UgyyuQcAzQAHsyIDxpZ4AaABAg", "text": "I''m grew up in Irvine as a child of the 80s. It was a great place to grow up.", "author": "@peterphan227", "like_count": 2, "published_at": "2025-08-08T13:09:24Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgwY3FTtcMUxy-Pk3wx4AaABAg", "text": "Irvine is for people with zero imagination. It\u2019s like loving franchise food. I grew up there and lived there in the mid seventies stayed until I turned thirty. So if you\u2019re uptight with control issues you will definitely feel at home in Irvine.", "author": "@plugnut4713", "like_count": 0, "published_at": "2025-07-29T13:37:37Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugz5EHubbTRv6gEzgcN4AaABAg", "text": "Get to the point! 4 minutes in and rambling on and on", "author": "@safewayguy", "like_count": 8, "published_at": "2025-07-22T12:44:04Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgwNALVh4T8Q4-1nXyd4AaABAg", "text": "The yogurt and pretzels something something also the escape gameee i played all of em (my favorite\u2019s prison break and gold rush) with my stupid cousins and my brother and my mom about 2 years ago", "author": "@AngelaLiu-z4j", "like_count": 0, "published_at": "2025-11-26T07:37:54Z", "parent_id": null, "video_id": "vtkr-PT4Bcs"}, {"id": "Ugzwlw-X_Mb5bLSrX0h4AaABAg", "text": "Nice", "author": "@Oko98l-oko98l", "like_count": 1, "published_at": "2025-10-09T20:55:05Z", "parent_id": null, "video_id": "vtkr-PT4Bcs"}, {"id": "UgxrRvhijxyfxiQ5F2J4AaABAg", "text": "If you work from home try Thailand or Vietnam. You get a better apartment with an ocean view free daily cleaning service for $850/month", "author": "@hash_value", "like_count": 0, "published_at": "2026-04-05T13:02:57Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "text": "I hate the extraneous noises of apartment living. That''s why I bought a house.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:07:15Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg.AU9leOfMix5AUNRnLyJwxT", "text": "Good for you!!!! House privacy is the best tbh", "author": "@theamericanexplorer", "like_count": 0, "published_at": "2026-03-15T12:34:20Z", "parent_id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "Ugx_SBkM3eJCHRl0F2l4AaABAg", "text": "Don\u2019t do it find another place another state", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:17:28Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg", "text": "Welcome to California. Welcome to Orange County the Irvine development company building huge compounds to shuffling people. That is their goal. Heavy taxes have a government and you will get nothing.", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:12:24Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg.APFXOwGwUjaAU9qUUTiJCP", "text": "Lady, you don''t know what you''re talking about. \n1) Renters don''t pay property taxes on their apartment. \n2) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \n3) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \n4) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:49:27Z", "parent_id": "UgzskPqRyemqVIE5NnR4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgwBv8B2eGpjpqi2XNt4AaABAg", "text": "Just one big heaping mound of regret why would you don\u2019t do it?", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:10:58Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "text": "I hope you love taxes and heavy government. Enjoy", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:56Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg.APFWlsu6i1DAU9rD00IBtZ", "text": "Lady, you don''t know what you''re talking about. \r\n1) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \r\n2) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \r\n3) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \r\nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.\r\n\r\nThe reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:55:48Z", "parent_id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg", "text": "Why would you buy a property in California?\ud83d\ude02 What an absolute joke", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:30Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rTCJbL30", "text": "Lady, the reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:58:01Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rnxx2Wqd", "text": "rockyrodes5 She doesn''t care about facts. She''s just a Republican with a hard need to vent against California, the 4th largest economy in the world.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T06:00:59Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgwEJXVJdrAg9Zo9bxd4AaABAg", "text": "\u2705 You might enjoy watching my video on Crystal Cove: https://youtu.be/n6cIfZeH4AI\r\n\u2705 Or Laguna Beach: https://youtu.be/Ek55xJ2md5E", "author": "@YellowProductions", "like_count": 5, "published_at": "2024-12-14T04:46:18Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxOihsJzcDHaYWeinN4AaABAg", "text": "I love arcade games at Dave and busters! \u2764\ud83d\ude0aalita", "author": "@AlitaKnight", "like_count": 0, "published_at": "2026-04-14T22:20:20Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgwwZRKq-Rulm0RqrUN4AaABAg", "text": "Habit is better than In-N-Out", "author": "@papagen00", "like_count": 0, "published_at": "2025-12-29T22:17:06Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqP3veKEKdUXzDqS14AaABAg", "text": "Irvine company is the worst", "author": "@negrobeard", "like_count": 0, "published_at": "2025-12-28T06:10:21Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugx_CoW_4zp_7Ou7rb94AaABAg", "text": "Thank you Sir \u2764\u2764\u2764\u2764", "author": "@kimyoung3484", "like_count": 3, "published_at": "2025-08-11T20:30:28Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgyWImsnajBNXf6SmEN4AaABAg", "text": "This is not. BIG mall as stated, it\u2019s okay. Beautiful spot but not much shopping options as an indoor mall.", "author": "@rcsc824sc8", "like_count": 0, "published_at": "2025-06-29T16:07:55Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugx1DKwXJkO4yGFvpL54AaABAg", "text": "Very Wonderful Shopping Center Video!!! I Love the Fountains!!!! F+L, Corey", "author": "@coreycoyle9548", "like_count": 5, "published_at": "2025-06-21T17:03:23Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugxh91Pu-6Byrk6-wDp4AaABAg", "text": "Be careful of that Cheesecake location. Got food poisoning there.", "author": "@Jenn_Jenn-w5i", "like_count": 0, "published_at": "2025-05-31T19:08:37Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg", "text": "I was from the Orange County area. I lived thier for 11 years and the Irvine Spectrum was one of my favorite spots to go shopping.", "author": "@matteocarlini27", "like_count": 5, "published_at": "2025-05-12T20:08:43Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg.AI1kkhc7uNIAIfahZXgjn-", "text": "I''m from London and I want to move to California why did you move out if I may ask", "author": "@Offline.e.e.e", "like_count": 1, "published_at": "2025-05-28T16:49:46Z", "parent_id": "UgxqQlnWff1lzcQ1wk94AaABAg", "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg.AI1kkhc7uNIAIg9cNlGdgp", "text": "@Offline.e.e.eI am still in California, I moved from Southern California because my mom got a job in Northern California", "author": "@matteocarlini27", "like_count": 1, "published_at": "2025-05-28T22:03:38Z", "parent_id": "UgxqQlnWff1lzcQ1wk94AaABAg", "video_id": "npR2EkyPXbo"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('university-park', '2026-04-29 05:49:17.898485', 3400.2223362668137, NULL, NULL, NULL, 0.046, 74.48, 2.48, 86.7, 68.0, 75.0, '["5tu2lcRB-RU", "KBIGvg1vR7s", "Ty30svQXSck", "6kctjxbUzD0", "upGNdii-EOU", "cZnCKKypvuU", "tp9iWSWI9HQ", "wbW7ATTytGw", "wfVhzCV1XFI"]', '[{"id": "UgxmpsJ_J40fgfyf3ix4AaABAg", "text": "Bro even get the direction of la and as wrong", "author": "@andyfu5283", "like_count": 0, "published_at": "2026-04-06T17:10:59Z", "parent_id": null, "video_id": "KBIGvg1vR7s"}, {"id": "Ugx49ROQkRFi2i4M0wl4AaABAg", "text": "Great video", "author": "@jarettrichards", "like_count": 0, "published_at": "2025-03-12T23:01:33Z", "parent_id": null, "video_id": "KBIGvg1vR7s"}, {"id": "UgxuakSkH-9yNOFW2pt4AaABAg", "text": "As of today, pretty much 1 M or above in GP.", "author": "@jennifer12366", "like_count": 1, "published_at": "2025-05-29T22:15:02Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgxuakSkH-9yNOFW2pt4AaABAg.AIikijwDg1JAIjO4EPAvkz", "text": "Thanks for watching our video! It''s Irvine so that sums up the market...However, if looking for a new home, builders are being very aggressive with offering incentives on upgrades and financing. Still not inexpensive though!", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-05-30T04:07:38Z", "parent_id": "UgxuakSkH-9yNOFW2pt4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "text": "Like like like like like like", "author": "@Yuriy_Beskrovniy", "like_count": 1, "published_at": "2023-03-24T16:56:35Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg.9ndyiur43ex9ne31aT96tR", "text": "Thanks Thanks Thanks! Really appreciate your watching our videos.", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-03-24T17:42:57Z", "parent_id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "Ugy-WHOhohgo7cO0omh4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-08-21T03:57:15Z", "parent_id": null, "video_id": "wbW7ATTytGw"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('westpark', '2026-04-29 05:50:02.604162', 3400.2223362668137, NULL, NULL, NULL, 0.095, 77.13, 2.48, 92.49, 68.0, 75.0, '["5tu2lcRB-RU", "iE-UImt8BCI", "BJrN1j2XbfI", "dDJ62hXVKms", "2mj3p1a-hb4", "2smaz4pGa00", "LES1YP1bTsk", "6kctjxbUzD0", "gOC7wjQ3lvY", "rQnl3wVdMtk", "LJgS5puZCfs"]', '[{"id": "UgxJL4xsqqw2x7PN1HF4AaABAg", "text": "Absolutely loved the video! \ud83c\udf1f Your content reflects real effort and creativity \u2014 it\u2019s truly impressive. \ud83d\ude0a I did notice a few small SEO improvements that could help your videos reach even more viewers. I\u2019d be happy to share some free tips if you\u2019re interested. Just let me know! \ud83d\ude4c", "author": "@unique_teachnology", "like_count": 0, "published_at": "2025-05-01T19:21:46Z", "parent_id": null, "video_id": "BJrN1j2XbfI"}, {"id": "UgxEu57K4H3P7Ljl7YN4AaABAg", "text": "\ud83d\udc4f\ud83d\udc4f\ud83d\udc4f", "author": "@jarettrichards", "like_count": 1, "published_at": "2025-04-28T17:53:10Z", "parent_id": null, "video_id": "BJrN1j2XbfI"}, {"id": "UgxEu57K4H3P7Ljl7YN4AaABAg.AHTT6bXcl6DAHTgCrRw_nr", "text": "Thank you!", "author": "@RyanSchulzeRealEstate", "like_count": 0, "published_at": "2025-04-28T19:56:21Z", "parent_id": "UgxEu57K4H3P7Ljl7YN4AaABAg", "video_id": "BJrN1j2XbfI"}, {"id": "UgyBO-IUbpvFJ64IsDd4AaABAg", "text": "Cool", "author": "@NikoBedi", "like_count": 0, "published_at": "2025-07-21T14:40:14Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "Ugwdq9REbfZ9Asyuvnl4AaABAg", "text": "Great Job Doug and Rachel!!  Wonderful tour \ud83c\udf89\ud83c\udf89", "author": "@TheNewportBeachLife", "like_count": 0, "published_at": "2025-02-15T22:35:19Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgxAhNYV25Tu-W-oW7J4AaABAg", "text": "Nice video.  Could you do a similar video on Orchard Hills?", "author": "@bladerunnin67", "like_count": 1, "published_at": "2024-04-25T20:17:46Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgxAhNYV25Tu-W-oW7J4AaABAg.A2f97hyH03oA2fDkDXRq17", "text": "Thank you! Yes, we sell homes in beautiful Orchard Hills, and we are working on a video to highlight this wonderful community. Thanks again!", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-25T20:58:07Z", "parent_id": "UgxAhNYV25Tu-W-oW7J4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgwUKjybrOqjj2uOCUl4AaABAg", "text": "I''ve lived in Irvine since 1968, when I hit a lottery I''ll be talking to you\ud83d\ude05 Great video!!!", "author": "@lionheartmerrill1069", "like_count": 2, "published_at": "2024-04-15T01:59:46Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgwUKjybrOqjj2uOCUl4AaABAg.A2ERWxyCz8oA2Gpipzzd6G", "text": "Thank you! \ud83d\ude0a", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-16T00:18:28Z", "parent_id": "UgwUKjybrOqjj2uOCUl4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgyQR1RFfq-zZfEM6DN4AaABAg", "text": "I can wait to live here thank you for the video and God bless you both \ud83d\ude4f\ud83c\udffe", "author": "@LamontEverage", "like_count": 2, "published_at": "2024-04-12T14:31:13Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgyQR1RFfq-zZfEM6DN4AaABAg.A28386gQrVfA2Gpl1SFQ9V", "text": "Thank you! \ud83d\ude0a \ud83d\ude4f", "author": "@swardstromgroup", "like_count": 0, "published_at": "2024-04-16T00:18:46Z", "parent_id": "UgyQR1RFfq-zZfEM6DN4AaABAg", "video_id": "dDJ62hXVKms"}, {"id": "UgwslS6Z_4fE6RqECYh4AaABAg", "text": "If you have visited Hidden Canyon, let us know your favorite aspect of this community in the COMMENTS below! \n\nFor Floor Plans of homes, or more information about Hidden Canyon, visit our community website - click here: https://LivingHiddenCanyon.com\nor email, call or text :\nEMAIL: Doug@SwardstromGroup.com or Rachel@SwardstromGroup.com\nPHONE: (949) 302-4883", "author": "@swardstromgroup", "like_count": 1, "published_at": "2024-04-12T01:14:45Z", "parent_id": null, "video_id": "dDJ62hXVKms"}, {"id": "UgzCSMMfbNe7rC0hoFJ4AaABAg", "text": "Just wow!! Awesome place for an awesome walk!!", "author": "@justwalk-travelasmrchannel1630", "like_count": 1, "published_at": "2021-05-06T06:17:23Z", "parent_id": null, "video_id": "2smaz4pGa00"}, {"id": "UgzCSMMfbNe7rC0hoFJ4AaABAg.9MzrTFBMeZ59N-hgBR8Z9E", "text": "Thank you! \ud83d\ude01", "author": "@presentthepresent794", "like_count": 0, "published_at": "2021-05-06T14:11:09Z", "parent_id": "UgzCSMMfbNe7rC0hoFJ4AaABAg", "video_id": "2smaz4pGa00"}, {"id": "UgzXVes_kNn2oddda3B4AaABAg", "text": "4) You don''t like to get ripped off doing errands", "author": "@hoaxnineteen", "like_count": 0, "published_at": "2026-04-24T19:27:08Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "text": "They lie about the safety in Irvine, I watched a couple flip their car and die on Alton, never made the news, kid recently died on his e-bike on keystone and regal, never makes the news or google search, no one can drive, we all know why\u2026", "author": "@SuperBaconFishing", "like_count": 3, "published_at": "2025-12-22T21:51:49Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugx_SIRBBRB3C3zoisF4AaABAg.AR2ibogH6dHAT-J0ogH1a-", "text": "Another reason is Chinese birth tourism, and nobody knows how to drive speak English", "author": "@IVvOOvVI", "like_count": 0, "published_at": "2026-02-09T07:04:30Z", "parent_id": "Ugx_SIRBBRB3C3zoisF4AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "Ugyu5pjHyapyDRLQtpN4AaABAg", "text": "lol poor people reasoning... lol very simple, you can''t afford it, what a dumbass", "author": "@andrewstephen6493", "like_count": 0, "published_at": "2025-11-13T17:50:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugxu-xIJAOWTG9oOhQR4AaABAg", "text": "Buddy it\u2019s the safest country in the us", "author": "@Yoojian12", "like_count": 1, "published_at": "2025-10-06T22:46:04Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "UgwzBZLRpM9mDrGfTlJ4AaABAg", "text": "The elites need Californians to disapear or move away, thats theirs now.", "author": "@bmc9504", "like_count": 0, "published_at": "2024-05-22T20:41:03Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg", "text": "What''s up with the outfit, my guy \ud83d\ude02 I''m from Irvine so maybe don''t live here if ya hate it so much! \u2764", "author": "@kikilee7162", "like_count": 1, "published_at": "2024-05-22T19:36:24Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugze1vj-7CZpBt9IEu94AaABAg.A3karJdRjfRA3kdlgWP805", "text": "Never said I hate it. \ud83d\ude0a", "author": "@LivingInIrvineCalif", "like_count": 0, "published_at": "2024-05-22T20:01:51Z", "parent_id": "Ugze1vj-7CZpBt9IEu94AaABAg", "video_id": "rQnl3wVdMtk"}, {"id": "UgxSQg0KVz7s-kVwDtR4AaABAg", "text": "U can keep that trash state", "author": "@pure_blood1", "like_count": 4, "published_at": "2024-05-22T15:45:33Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "Ugzi_kMqXU1Iwoi_6754AaABAg", "text": "CA house and rental prices,gas price, grocery prices, restaurant prices,insurance costs,repair costs", "author": "@coletanner5193", "like_count": 2, "published_at": "2024-05-22T13:30:15Z", "parent_id": null, "video_id": "rQnl3wVdMtk"}, {"id": "UgzrE8X4KM7TBl9OTMd4AaABAg", "text": "\ud83c\udf34\ud83c\udf1e\ud83c\udf0a Considering a move to Southern California? \ud83c\udf0a\ud83c\udf1e\ud83c\udf34\n\ud83d\udcde\ud83c\udfe1 Need expert advice? Reach out to us! \ud83c\udfe1\ud83d\udcde\n\ud83e\udd33 Call or Text: 562.357.7768\n\ud83d\udce7 Email: SteveBatiz@NextHomeWest.com", "author": "@LeftCoastLiving", "like_count": 0, "published_at": "2023-06-23T22:00:02Z", "parent_id": null, "video_id": "LJgS5puZCfs"}, {"id": "Ugzm1yDXYqB4KXD7sAh4AaABAg", "text": "I live in the Woodbridge neighborhood in Irvine and I love it", "author": "@DrJenniferY", "like_count": 1, "published_at": "2025-12-16T23:30:33Z", "parent_id": null, "video_id": "LJgS5puZCfs"}, {"id": "Ugzm1yDXYqB4KXD7sAh4AaABAg.AQoS8dwYdVnAR600SNUKfo", "text": "Irvine is a nice city.", "author": "@LeftCoastLiving", "like_count": 0, "published_at": "2025-12-24T04:30:20Z", "parent_id": "Ugzm1yDXYqB4KXD7sAh4AaABAg", "video_id": "LJgS5puZCfs"}, {"id": "UgwyIcHz-LLYYVNu9jx4AaABAg", "text": "Its so sad that its so expensive.", "author": "@leticiaurbach1720", "like_count": 0, "published_at": "2023-05-30T14:49:05Z", "parent_id": null, "video_id": "LJgS5puZCfs"}, {"id": "UgwyIcHz-LLYYVNu9jx4AaABAg.9qLGOhw-Q-j9qME3vdxSwH", "text": "It is but it\u2019s all relative. Where do you live now?", "author": "@LeftCoastLiving", "like_count": 0, "published_at": "2023-05-30T23:48:00Z", "parent_id": "UgwyIcHz-LLYYVNu9jx4AaABAg", "video_id": "LJgS5puZCfs"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
