 this! Thank you!", "author": "@Armchair-Investor", "like_count": 0, "published_at": "2023-04-08T20:09:46Z", "parent_id": null, "video_id": "Z9SFLO1lTbc"}, {"id": "UgwabJ0N6c8kTleduFt4AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\r\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-01-27T02:48:42Z", "parent_id": null, "video_id": "BLJ74DQS9Zc"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
