ll, "video_id": "IoPcQHghy5I"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('portola-springs', '2026-04-29 05:42:45.797037', 3400.2223362668137, NULL, NULL, NULL, 0.0, 72.0, 2.48, 72.34, 75.0, 82.0, '["aV-Kx0OghxQ", "H36pybDkocE", "1oAzwDwETJk", "3Y1n9pb70NM", "zu5GyEK_SSo", "q_ygaSlxk48"]', '[{"id": "UgwPc8g9oF3J4okevuV4AaABAg", "text": "North Irvine is the most safest and cleanest community in socal. It also has the best public schools in California. Basically a eutopia if you can afford it.", "author": "@Domane-mh8wg", "like_count": 0, "published_at": "2026-02-16T23:59:06Z", "parent_id": null, "video_id": "H36pybDkocE"}, {"id": "UgxpeMJwYtRQtiHs8_N4AaABAg", "text": "Not a pedestrian in sight.  Car culture.  It\u2019s all asphalt.  Hey from pedestrian Boston.  \ud83d\udc4b\ud83c\udffc", "author": "@tabithan2978", "like_count": 0, "published_at": "2026-02-14T09:51:36Z", "parent_id": null, "video_id": "H36pybDkocE"}, {"id": "Ugy5bNUuAfpQD22SxHJ4AaABAg", "text": "Check out", "author": "@carinatruong6446", "like_count": 0, "published_at": "2026-03-19T02:33:29Z", "parent_id": null, "video_id": "zu5GyEK_SSo"}, {"id": "UgxTI3SOwLtbMdUPz-R4AaABAg", "text": "Contact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======\r\n\ud83d\udcf1Call or text: 949-285-1207   \r\n\ud83d\udce7Email: info@livinginirvineca.com\r\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":\r\nhttps://bit.ly/3x8Lsnq", "author": "@BruceClark", "like_count": 1, "published_at": "2022-07-24T03:06:02Z", "parent_id": null, "video_id": "q_ygaSlxk48"}, {"id": "UgxTI3SOwLtbMdUPz-R4AaABAg.9dqmWBQCQRw9f-5Pr930Ci", "text": "Thank you for watiching.  Let us know if you have any questions we can answer for you.", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-08-21T14:24:29Z", "parent_id": "UgxTI3SOwLtbMdUPz-R4AaABAg", "video_id": "q_ygaSlxk48"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('quail-hill', '2026-04-29 05:43:41.375373', 3400.2223362668137, NULL, NULL, NULL, 0.052, 74.81, 2.48, 73.2, 68.0, 75.0, '["wfUwD9EJbgE", "9FNC3I4dx3Q", "SRTdUq4VlCY", "sNvRIE9bfXE", "GJOu82_tykg", "4grkq_B0cHE", "WSjnL6rSyHw", "srvzTpHOj3w"]', '[{"id": "UgyGtrnSNysZ3WcxN1Z4AaABAg", "text": "I appreciate the Resilience of property prices in irvine so much", "author": "@alexanderschwarm7755", "like_count": 0, "published_at": "2024-02-11T09:15:31Z", "parent_id": null, "video_id": "wfUwD9EJbgE"}, {"id": "Ugx04OTWFb4eYHKhTXZ4AaABAg", "text": "New construction tours model home and existing homes tours? updates!? Boots on ground visit new builds see available model & spec inventory! Master planned boots on site tours!?\ud83e\udde4\ud83d\ude42\ud83d\udc4d\ud83d\udeb5\ud83c\udffb\u200d\u2642\ufe0f", "author": "@michaelsyufy7733", "like_count": 0, "published_at": "2024-02-10T19:48:06Z", "parent_id": null, "video_id": "wfUwD9EJbgE"}, {"id": "UgyYrSDj5pqvCsm8OU54AaABAg", "text": "I am also an original owner at Quail Hill since 2005.  My favorite features are the pools.  I swim laps multiple times a week all year long!   The trial to Laguna Beach is a close second!", "author": "@chrisknotz1984", "like_count": 0, "published_at": "2025-08-24T17:25:49Z", "parent_id": null, "video_id": "SRTdUq4VlCY"}, {"id": "UgyYrSDj5pqvCsm8OU54AaABAg.AMDFmaXFmzyANK0aOYfF_M", "text": "Thanks for sharing! The pools are a great amenity, and the trail to the beach is very popular too!", "author": "@swardstromgroup", "like_count": 0, "published_at": "2025-09-21T04:59:10Z", "parent_id": "UgyYrSDj5pqvCsm8OU54AaABAg", "video_id": "SRTdUq4VlCY"}, {"id": "UgwD6fnbtKmSzwZgmFR4AaABAg", "text": "If you have been to Quail Hill, let us know your favorite feature of this amazing community in the COMMENTS below! \ud83d\ude0a\n\nFor more information about Quail Hill, visit our community website - click here: https://LivingQuailHill.com\nor email, call or text :\nEMAIL: Doug@SwardstromGroup.com or Rachel@SwardstromGroup.com\nPHONE: (949) 302-4883", "author": "@swardstromgroup", "like_count": 3, "published_at": "2023-09-13T22:33:56Z", "parent_id": null, "video_id": "SRTdUq4VlCY"}, {"id": "Ugxq3AShsDcgstBGQ1N4AaABAg", "text": "u want a shoutout? :D", "author": "@ava7342", "like_count": 0, "published_at": "2020-08-25T17:14:18Z", "parent_id": null, "video_id": "sNvRIE9bfXE"}, {"id": "Ugy5SjJw5j246wihitd4AaABAg", "text": "VEry good", "author": "@SaidulCreative-j1r", "like_count": 1, "published_at": "2025-07-12T20:45:29Z", "parent_id": null, "video_id": "srvzTpHOj3w"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('eastwood-village', '2026-04-29 05:45:01.143824', 3400.2223362668137, NULL, NULL, NULL, 0.012, 72.65, 2.48, 75.74, 75.0, 82.0, '["CSpYOm3QDyA", "3ohn616ip-4", "J4RvRyGm7KE", "3dUe2PbGqhw", "K7c5UHfM5YM", "BEYFAunJ9NY", "jxisHvvsGnk"]', '[{"id": "UgyVOkGgoLqQP94GCmB4AaABAg", "text": "Cali is ridiculously expensive !  Praise God I live in the Midwest were a house like this is $300,000 for my area", "author": "@HosCreates", "like_count": 0, "published_at": "2023-01-18T20:06:12Z", "parent_id": null, "video_id": "CSpYOm3QDyA"}, {"id": "UgyxED5dGEsWGcFS1sl4AaABAg", "text": "Nice homes and very helpful info! But the cost!", "author": "@GeorgeWilliams-me7hy", "like_count": 1, "published_at": "2024-09-19T21:09:08Z", "parent_id": null, "video_id": "3ohn616ip-4"}, {"id": "UgyxED5dGEsWGcFS1sl4AaABAg.A8_krVbG61sA8cAUt9rDvO", "text": "Great city and community:  not inexpensive to live in Irvine, but the safety, schools, location make this a very attractive place to live! Thanks for watching :)", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2024-09-20T19:40:19Z", "parent_id": "UgyxED5dGEsWGcFS1sl4AaABAg", "video_id": "3ohn616ip-4"}, {"id": "UgzZbhFuTodQI-Bmzox4AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California or surrounding areas?\ud83c\udf34\n\ud83d\udcf1Call or text:  949-285-1207\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-01-08T02:52:54Z", "parent_id": null, "video_id": "3ohn616ip-4"}, {"id": "Ugw7EQwFBslsaWNPE0V4AaABAg", "text": "I love the video!! \ud83d\ude0a", "author": "@beautybyblair4847", "like_count": 2, "published_at": "2022-10-12T06:52:47Z", "parent_id": null, "video_id": "K7c5UHfM5YM"}, {"id": "Ugw7EQwFBslsaWNPE0V4AaABAg.9h4B2ya3K1-9h4Dwh7iZVi", "text": "Thank you! We\u2019re so happy with the video too! \u2764", "author": "@orangecountyrealestatepodcast", "like_count": 1, "published_at": "2022-10-12T07:18:00Z", "parent_id": "Ugw7EQwFBslsaWNPE0V4AaABAg", "video_id": "K7c5UHfM5YM"}, {"id": "Ugw7EQwFBslsaWNPE0V4AaABAg.9h4B2ya3K1-9h4EDLtfDvu", "text": "Don\u2019t forget to like, share it, and subscribe too! \ud83d\udc4d\ud83d\ude0a", "author": "@orangecountyrealestatepodcast", "like_count": 0, "published_at": "2022-10-12T07:20:25Z", "parent_id": "Ugw7EQwFBslsaWNPE0V4AaABAg", "video_id": "K7c5UHfM5YM"}, {"id": "Ugw7EQwFBslsaWNPE0V4AaABAg.9h4B2ya3K1-9h7nyIof6ik", "text": "This is an amazing video and beautiful home!  Wow!", "author": "@thepagroup4910", "like_count": 2, "published_at": "2022-10-13T16:39:15Z", "parent_id": "Ugw7EQwFBslsaWNPE0V4AaABAg", "video_id": "K7c5UHfM5YM"}, {"id": "UgwAUq4zB7xmK9jufmp4AaABAg", "text": "I love how in depth your videos are!", "author": "@Vanillalatte22433", "like_count": 1, "published_at": "2026-03-31T04:18:29Z", "parent_id": null, "video_id": "jxisHvvsGnk"}, {"id": "UgwAUq4zB7xmK9jufmp4AaABAg.AV-kl_ph3mCAV6QPes1nWJ", "text": "Thank you so much! We try to give the most detailed look at all our properties to create higher demand for the final sale!", "author": "@MonicaCarrRealEstateGroup", "like_count": 0, "published_at": "2026-04-02T18:26:32Z", "parent_id": "UgwAUq4zB7xmK9jufmp4AaABAg", "video_id": "jxisHvvsGnk"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('lower-peters-canyon', '2026-04-29 05:46:04.363016', 3400.2223362668137, NULL, NULL, NULL, 0.065, 75.51, 2.48, 77.64, 68.0, 75.0, '["IiSrBf7tBYs", "OmGbMh3gDA8", "A-5c-WZyLl8", "PUr6_cNtIOs", "iA4ut4sUad8", "kPrRqkQPz0s", "GsfMeu9sD5o", "bPSGJAYMRCY", "vFUfMl_3WoU", "vsKPsXWbV8U", "rPwQ4UpLGWk"]', '[{"id": "UgzN3LhpAGfervhPcIh4AaABAg", "text": "I am going to try Jeffery Open Space Trail to Peter''s Canyon Trail via Hicks canyon trail. That is the nice thing about Irvine, all the trails interconnect.", "author": "@robinrussell7965", "like_count": 1, "published_at": "2023-07-20T17:40:20Z", "parent_id": null, "video_id": "vsKPsXWbV8U"}, {"id": "UgzN3LhpAGfervhPcIh4AaABAg.9sOtXa6kd6r9sP9_KFdAol", "text": "That''s a good ride, should be fun.", "author": "@greatbikeridesofsocal271", "like_count": 0, "published_at": "2023-07-20T20:09:15Z", "parent_id": "UgzN3LhpAGfervhPcIh4AaABAg", "video_id": "vsKPsXWbV8U"}, {"id": "UgzuSvYaajTMaMuhMwp4AaABAg", "text": "Taking about roughing it ! Great ride !", "author": "@mustangmorris53", "like_count": 1, "published_at": "2025-11-18T01:15:24Z", "parent_id": null, "video_id": "rPwQ4UpLGWk"}, {"id": "UgxJ986E0LiyN-MtFdd4AaABAg", "text": "Dirt, and not only that, but I''ve never seen that trail before. I''ll have to check that one out. So close to Mountains to the Sea, but I never knew. Thanks for sharing, or should I thank Google maps?", "author": "@artblakey4159", "like_count": 1, "published_at": "2025-11-05T10:03:28Z", "parent_id": null, "video_id": "rPwQ4UpLGWk"}, {"id": "UgxJ986E0LiyN-MtFdd4AaABAg.AP8RBYJPLgtAPA24VTN5vX", "text": "Either/both \ud83d\ude42", "author": "@greatbikeridesofsocal271", "like_count": 0, "published_at": "2025-11-06T01:02:32Z", "parent_id": "UgxJ986E0LiyN-MtFdd4AaABAg", "video_id": "rPwQ4UpLGWk"}]', 1.0, '{"sources": {"zori_csv": true, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": true, "irvine_crime_source": "local_csv+density", "crime_api": true, "crime_api_source": "local_csv+density", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": true, "night_activity_source": "local_viirs"}}');
