INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('8834c184-43f9-4873-8487-89df19223326', 'irvine-spectrum', 'youtube', 'Ugz7l40YP-WOxEVmDqF4AaABAg', NULL, '2026-04-16 21:06:47', NULL, 'My son is 17, Northwood high school. GPA over 3.5. He''s had a good high school experience. He''s not taking all AP classes and not getting tudors. Yes, if you want over a 4.0 there''s more work involved. But going to school in Irvine doesn''t require crazy amounts of work and tudors if you don''t want to go to an Ivy league school. You can still get into fine schools, haha.', NULL, '@ChrisRivera-lz3lo', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('1d1fab8c-43b2-4608-a450-c7f10e484a4b', 'irvine-spectrum', 'youtube', 'UgyRk3mrSkDvvRbOrW94AaABAg', NULL, '2026-03-20 16:57:45', NULL, 'I raised all 3 of my kids in Woodbridge, spent half of my 72 years there. No complaints', NULL, '@robertkendall1037', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('b7619a31-9fbe-49bf-ab19-1471324488bc', 'irvine-spectrum', 'youtube', 'Ugwep9dq5yI_FgL7TkV4AaABAg', NULL, '2026-02-15 07:36:33', NULL, 'A family I am close to with two young children moved from Pasadena to Irvine for work. They liked Pasadena, but they have grown to like Irvine. Their rent is higher in Irvine, but they are in a nice place that is not 100 years old.', NULL, '@prrosenkrantz', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('aff55be6-5a06-4846-83b8-bdb076605a80', 'irvine-spectrum', 'youtube', 'UgyYa8UWhXGsOUlkMpx4AaABAg', NULL, '2026-01-12 03:22:49', NULL, '🤔....mmm Irvine way hotter??? Somebody wants to sell more houses closer to the beach...', NULL, '@Franciscodelporto', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('b4058a70-23f2-4183-82a1-23254fcfdfba', 'irvine-spectrum', 'youtube', 'Ugwre5ef-NVNhqbLa1N4AaABAg', NULL, '2025-11-19 15:58:27', NULL, 'It takes time to understand Irvine.  But once you live there after a year you realize why it was built the way it is with shopping centers facing inward to prevent crime, pedestrians, and homeless.  And how it was built with 3 to 4 lane throughways to improve traffic and minimize slowing by moving entrances to shopping centers to inner streets.  And of course the master planned communities designed to mix apartments, condos and SFHs to provide diversity within each village.  Then there’s the massive amount of land dedicated to parks and biking.  Irvine is intentionally the anti-city designed to improve the quality of family life.', NULL, '@ap774', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('1a16fbbc-b1e5-4ac6-a440-733bfc35e8fb', 'irvine-spectrum', 'youtube', 'UgybuXEX8V9EEdCu6IV4AaABAg', NULL, '2025-08-25 23:26:09', NULL, 'Irvine is so over built and the traffic is horrible. Most of the shopping centers are so crowded it can be hard to find a parking spot. It was a great place 45 years ago but no more!', NULL, '@MikeB-in1nd', 2.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('a694f336-9d7d-4adc-8418-25dfa53fea09', 'irvine-spectrum', 'youtube', 'UgybuXEX8V9EEdCu6IV4AaABAg.AMGToWgnO7lAVaacHdhsbx', NULL, '2026-04-14 21:00:58', NULL, 'they didnt have internet 45 years ago so it cant have been that good, may as well say 500 years ago for all it relates to anyone today', 'UgybuXEX8V9EEdCu6IV4AaABAg', '@drinkwater9891', 0.0);
