INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('baa8d487-ec1b-4657-a85a-9c4d81fcdc94', 'irvine-spectrum', 'youtube', 'UgwY3FTtcMUxy-Pk3wx4AaABAg', NULL, '2025-07-29 13:37:37', NULL, 'Irvine is for people with zero imagination. It’s like loving franchise food. I grew up there and lived there in the mid seventies stayed until I turned thirty. So if you’re uptight with control issues you will definitely feel at home in Irvine.', NULL, '@plugnut4713', 0.0);
