INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('f14ed385-af9c-4e87-8bf1-62d9095fef9e', 'university-town-center', 'youtube', 'Ugwgx2WHOSrfo0MT0N94AaABAg.9uuruM-AYdh9uwFVrcJXPm', NULL, '2023-09-21 18:58:02', NULL, 'Hi there, Irvine is generally pretty safe! Camino Del Sol is a smaller community and is closer to campus/other housing than Vista Del Campo and Vista Del Campo Norte, so there is more traffic and events happening regularly. Vista Del Campo is on the outskirts of campus so there is minimal traffic/activity happening in that area but some of my friends who lived in that area enjoyed it. What was sometimes challenging was how far it was from campus.', 'Ugwgx2WHOSrfo0MT0N94AaABAg', '@a2fIrvine', 2.0);
