INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('b40d0e33-801e-40aa-a9ec-beb31bb16739', 'northwood', 'youtube', 'UgztpdqR7Fa8IVIC-894AaABAg', NULL, '2024-08-26 23:49:04', NULL, 'Anyone looking for a new or newer built home in Irvine, especially in the newer neighborhoods, you better be prepared to pay north of $2.0MM for an average size home.  Considering you will be assessed property taxes at the market value of the home along with two HOAs, even if you have $1.0MM to put as down payment, your monthly bill for all of the above will still be a boat load ! ! !
