INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('33375b46-cc9e-4bc0-96b8-ed2e679f512e', 'northwood-pointe', 'youtube', 'UgzTTJyb8aF-pcvuY4Z4AaABAg', NULL, '2024-05-18 19:14:46', NULL, 'Thank you. I really appreciate 🙏 your video. I had looked at several Irvine Company apartments a few years ago. But I was not in a position to afford one. Center Point, after seeing your video is now my favorite. I do remember going there and how pretty the community is, resort like, greenery, stunning property. As you said, it is like it''s own City. Second choice which I saw was The Park. I had seem more, but these two are still my top two. I will go back to work this year 2024 or early 2025. Planning to go see these two apartments, probably will pick Center Point, as it has more to offer. 
