INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('8c7d0fc4-a504-4527-a374-80fd63d4e9ca', 'orangetree', 'youtube', 'Ugya89fVSXDbIx7OUQx4AaABAg', NULL, '2025-11-23 07:00:36', NULL, 'A lot of the Asian families live here and we can call the city of Irvine, The Asian beverlyhills.', NULL, '@RickAutor-i5c', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('824810b9-6140-4195-8f9f-17c15dc87687', 'orangetree', 'youtube', 'UgxOYjvECfzwAaHTlRl4AaABAg', NULL, '2025-09-20 20:52:54', NULL, 'I have a question. I consider moving to Irvine from Türkiye, but my husband is a sergeant so techically he can''t work for his own job anymore, he has to do idk detailing, storage doordash idk something will work for him in the end, but for me I am anEnglish teacher in a government school for almost 10 years here, I''ve got my TESOL, sertificates etc. Is it a smart move for us to live in Irvine because actually I want to be in somewhere safe and with good schools also a good weather. Please, inform me sincerely. Thank you all <3', NULL, '@hellobuss', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('d906ab8e-199a-4804-bd82-ff04ff80cec8', 'orangetree', 'youtube', 'UgxOYjvECfzwAaHTlRl4AaABAg.ANJ8wu5SExvANaUaQwgk3N', NULL, '2025-09-27 23:48:24', NULL, 'Irvine is an amazing place to live! There are pros and cons to every city, but we love it here. ❤', 'UgxOYjvECfzwAaHTlRl4AaABAg', '@LivinginOrangeCountyExperts', 1.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('fadc7ec5-5ab2-4121-b3f4-a45a9155aa06', 'orangetree', 'youtube', 'UgzH74Wiz2kOe5ugAkB4AaABAg', NULL, '2025-08-10 21:32:29', NULL, 'Huge population of Chinese expats, alot of police patrols (theyre police everywhere, hence the reason why the city was voted one of safest cities in US)  high cost of living ( rent is really high) , etc. These are some common aspects of Irvine. Its a nice town and I work there but would never considered living there, people in Irvine just arent friendly and also Ive gotten pulled over by IPD multiple times for no legitimate reason just car checks ( hence the city safety mentioned above)', NULL, '@followme82365', 0.0);
