INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('a166b9b0-0721-4901-8c34-9f4365157f4a', 'orchard-hills', 'youtube', 'UgxkscJaVeqVW7ia_BZ4AaABAg.ASHycRmz6gwASX7PeScfZk', NULL, '2026-01-28 13:45:49', NULL, 'Thank you for watching 👍', 'UgxkscJaVeqVW7ia_BZ4AaABAg', '@Living_in_LosAngeles', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('7d237097-c2bd-4318-9fa5-8d85d999d928', 'orchard-hills', 'youtube', 'UgxwtWKqTKwlROBCfZ14AaABAg', NULL, '2026-01-06 04:15:03', NULL, 'The long catwalk suspended in the air makes me very nervous, especially with little kids and elderly, regardless of the glass banister. The primary bathroom is beautiful, but I''m disappointed in the layout. The primary bedroom should come first after the entrance, the bathroom and closet after. Also, I feel the master closet should be bigger for the price of the house. The size of the primary bedroom, bathroom, and closet matters for a couple. Just my honest thoughts.', NULL, '@timothykassisieh9701', 0.0);
