INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('9b562571-d764-4e0a-8d25-ed8949e6dd1a', 'orchard-hills', 'youtube', 'Ugz8RowMGPajvyrV4WJ4AaABAg', NULL, '2025-11-02 05:51:46', NULL, 'For a little over $4 million, the Saddle Crest community offers larger, better appointed homes on larger lots and not too far from the Orchard Hills area, but without the exorbitant price premium. Ra - you should check them out and do a video on those homes. The "Sage" residence offers 5700 sq ft, a 4 car garage space, 2 powder rooms, primary bath with dual water closets and two closets, and even an elevator (which is great for getting heavy stuff to the 2nd floor even for us younger peeps!). And the lots are larger, too.  Worth a look for sure.', NULL, '@texastriguy', 2.0);
